window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q17"]=window.__LIBQ["tien-nghich"]["q17"]||{};window.__LIBQ["tien-nghich"]["q17"]["techniques"]={"updatedAt":"2026-07-15","count":127,"techniques":[{"id":"cam-che-dai-tran-dai-hon-mon","name":"Cấm chế đại trận Đại Hồn Môn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Đại Hồn Môn"],"blurb":"Đại trận bao bọc sơn môn Đại Hồn Môn, ngăn người ngoài xâm nhập và liên động với thần thức cao thủ trong tông. Vương Lâm phải quan sát mười ngày, dùng cấm chế bổn nguyên mô phỏng dao động mới xâm nhập thành công.","detail":"Trận pháp bên ngoài sơn môn bao bọc toàn dãy núi, tạo lực bài xích với người không phải đệ tử Đại Hồn Môn. Dao động của trận biến hóa theo thân phận đệ tử ra vào, đồng thời khi cao thủ Không Kiếp sơ kỳ tản thần thức, đại trận lập tức phong tỏa. Vương Lâm dựa vào quan sát lâu ngày và cấm chế bổn nguyên để triệt tiêu, mô phỏng biến hóa rồi lẩn vào theo đệ tử nhập trận.","dinhDanh":"goc","thuocTinh":"cấm chế, hồn phách, hộ sơn","dacDiem":"Biến hóa theo thân phận đệ tử và có thể phong tỏa liên động với thần thức toàn năng trong Đại Hồn Môn.","congNang":["Bao bọc sơn môn, phát hiện người ngoài không phải đệ tử khi chạm vào trận @c1725","Tạo phong tỏa khi thần thức cao thủ Không Kiếp sơ kỳ quét qua dãy núi @c1725"],"trangThai":"đang vận chuyển","capNhatToi":"@c1725","tabs":{"tienTrinh":[{"chuong":"@c1725","loai":"xuất hiện","importance":"normal","giaiDoan":"hộ sơn Đại Hồn Môn","text":"Cấm chế đại trận Đại Hồn Môn được Vương Lâm quan sát mười ngày trước khi bị hắn dùng cấm chế bổn nguyên mô phỏng dao động để xâm nhập.","anchor":"cấm chế đại trận ở bên ngoài sơn môn cực kỳ lợi hại, nếu không phải là đệ tử của tông phái một khi chạm phải lập tức sẽ bị Đại Hồn Môn phát hiện ra ngay"}]},"nguon":["@c1725"]},{"id":"cam-che-bon-nguyen-mo-phong","name":"Cấm chế bổn nguyên mô phỏng","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Cấm chế bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Cách vận dụng cấm chế bổn nguyên của Vương Lâm để mô phỏng cấm chế trong ngọc giản mở tầng sáng. Nhờ đó hắn vượt qua phòng hộ Viêm Mạch Phong mà không gây động tĩnh.","detail":"Trong lúc Tống Anh dùng ngọc giản mở tầng sáng phòng hộ, Vương Lâm phân tách thần thức nghiên cứu cấm chế bên trong rồi lấy cấm chế bổn nguyên mô phỏng lại cơ chế đó. Cách làm này giúp hắn vô thanh vô tức tiến vào khu vực bị phong bế của Đại Hồn Môn.","thuocTinh":"cấm chế","uyLuc":"Có thể mô phỏng cơ chế cấm chế của ngọc giản để qua mặt tầng sáng phòng hộ bên ngoài Viêm Mạch Phong.","dacDiem":"Thi triển kín đáo, dựa trên khả năng nghiên cứu và mô phỏng cấm chế của Vương Lâm.","congNang":["Mô phỏng cấm chế trong ngọc giản mở tầng sáng để xâm nhập khu vực phòng hộ @c1726"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1726","tangDatToi":"vận dụng để mô phỏng ngọc giản mở tầng sáng","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1726","loai":"thi triển","importance":"normal","giaiDoan":"Vượt tầng sáng Viêm Mạch Phong","text":"Vương Lâm dùng cấm chế bổn nguyên mô phỏng lại ngọc giản mở tầng sáng, nhờ đó vô thanh vô tức tiến vào bên trong Viêm Mạch Phong.","anchor":"lấy cấm chế bổn nguyên mô phỏng lại ngọc giản vừa rồi, vô thanh vô tức tiến vào bên trong"}]},"capNhatToi":"@c1726","nguon":["@c1726"]},{"id":"suong-mu-phong-be-de-tu-trung-tam-dai-hon-mon","name":"Sương mù phong bế đệ tử trung tâm Đại Hồn Môn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông đặc quyền","phamCap":"không rõ","hePhai":"Đại Hồn Môn","soHuu":["Phàn San Lộ"],"blurb":"Sương mù phong bế do đệ tử trung tâm Đại Hồn Môn phóng ra khi bế quan hoặc tự bảo vệ. Phàn San Lộ dùng nó để phong bế động phủ sau khi nghe Vương Lâm gọi tên qua thần thức.","detail":"Khi Phàn San Lộ vung tay, sương mù từ thắt lưng lan ra, phong bế toàn bộ khí tức trong động phủ và ngăn thần thức bên ngoài dò xét trong thời gian ngắn. Nàng giải thích đây là thứ đệ tử trung tâm Đại Hồn Môn dùng khi bế quan, nên dù sư tôn ở gần cũng khó lập tức phát hiện.","thuocTinh":"phong bế khí tức","uyLuc":"Có thể ngăn thần thức bên ngoài dò xét động phủ trong thời gian ngắn.","dacDiem":"Gắn với thân phận đệ tử trung tâm Đại Hồn Môn.","congNang":["Phong bế khí tức trong động phủ và ngăn thần thức ngoại lai dò xét trong thời gian ngắn @c1726"],"nguoiTu":[{"ten":"Phàn San Lộ","tuChuong":"@c1726","tangDatToi":"có thể phóng sương mù phong bế động phủ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1726","loai":"thi triển","importance":"normal","giaiDoan":"Phong bế động phủ Phàn San Lộ","text":"Phàn San Lộ dùng sương mù phong bế động phủ khi nghe Vương Lâm gọi tên, khiến bên ngoài khó dò xét khí tức bên trong.","anchor":"sương mù là thứ đệ tử trung tâm của Đại Hồn Môn chúng ta bế quan lan ra"}]},"capNhatToi":"@c1726","nguon":["@c1726"]},{"id":"hoa-bon-nguyen-tu-luyen","name":"Hỏa bổn nguyên tu luyện","cn":"","aliases":["Hỏa bổn nguyên tu luyện cắn nuốt ý chí"],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Hỏa bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Phương thức Vương Lâm mượn địa hỏa chủ mạch để hấp thu hỏa bổn nguyên và cắn nuốt ý chí địa hỏa, nhằm ngưng tụ bổn nguyên chân thân.","detail":"Trong thạch thất địa hỏa chủ mạch, Vương Lâm hấp thu nhiệt độ bốn phía thành hỏa bổn nguyên, sau đó dung hợp khí tức với chủ mạch và chuyển sang cắn nuốt ý chí địa hỏa. Quá trình này thúc đẩy bổn nguyên chân thân biến đổi, phần đầu vốn mang hình Chu Tước bắt đầu hiện ra dấu hiệu chuyển hóa.","thuocTinh":"Hỏa","nguonGoc":"Tu luyện trong địa hỏa chủ mạch dưới Viêm Mạch Phong.","yeuCau":"Cần tiếp xúc và dung hợp với địa hỏa chủ mạch, đồng thời cắn nuốt ý chí địa hỏa.","uyLuc":"Có thể thúc đẩy bổn nguyên chân thân của Vương Lâm dần hoàn thiện khi cắn nuốt ý chí chủ mạch.","dacDiem":"Trọng tâm là hấp thu hỏa bổn nguyên lực và cắn nuốt ý chí địa hỏa chứ không chỉ tu luyện trong nhiệt lực bên ngoài.","trangThai":"đang được Vương Lâm tu luyện","capNhatToi":"@c1727","congNang":["Cắn nuốt ý chí địa hỏa để ngưng tụ bổn nguyên chân thân @c1727"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1727","tangDatToi":"đang cắn nuốt ý chí địa hỏa","trangThai":"đang tu luyện"}],"tabs":{"tienTrinh":[{"chuong":"@c1727","loai":"xuất hiện","importance":"normal","giaiDoan":"Cắn nuốt ý chí địa hỏa","text":"Vương Lâm hấp thu hỏa bổn nguyên trong địa hỏa chủ mạch, sau đó cắn nuốt ý chí chủ mạch để thúc đẩy bổn nguyên chân thân biến đổi.","anchor":"Chỉ có cắn nuốt luồng ý chí này, trở thành thủ lành của địa hỏa trên Thiên Ngưu Châu"}]},"nguon":["@c1727"]},{"id":"than-thong-mat-quy-dai-hon-mon","name":"Thần thông mặt quỷ Đại Hồn Môn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Viêm Loan"],"blurb":"Thần thông của Đại Hồn Môn được Viêm Loan thi triển qua cổ kính đồng xanh để truy sát Vương Lâm trong địa hỏa chủ mạch.","detail":"Khi thi triển, cổ kính đồng xanh phóng ra hắc khí hóa thành mặt quỷ khổng lồ, tốc độ cực nhanh, rút ngắn khoảng cách với mục tiêu trong thời gian ngắn.","thuocTinh":"Hắc khí, mặt quỷ","uyLuc":"Mặt quỷ truy sát có tốc độ rất nhanh, từng áp sát Vương Lâm chỉ còn ba mươi trượng trong địa hỏa chủ mạch.","dacDiem":"Được thi triển thông qua cổ kính đồng xanh của Viêm Loan.","congNang":["Triệu hồi mặt quỷ từ hắc khí qua cổ kính để truy sát mục tiêu @c1728"],"nguoiTu":[{"ten":"Viêm Loan","tuChuong":"@c1728","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1728","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát trong địa hỏa chủ mạch","text":"Viêm Loan dùng cổ kính đồng xanh phóng hắc khí hóa thành mặt quỷ khổng lồ truy sát Vương Lâm.","anchor":"Thần thông mặt quỷ của Đại Hồn Môn"}]},"capNhatToi":"@c1728","nguon":["@c1728"]},{"id":"bat-cuc-tien-dao","name":"Bát Cực Tiên Đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Tiên Tổ","soHuu":["Tiên Tổ","Vương Lâm"],"blurb":"Bát Cực Tiên Đạo là đạo thuật do Tiên Tổ thi triển trong ảo giác mà Vương Lâm chứng kiến khi hấp thu ý chí hỏa long hồn, về sau được chính Vương Lâm đem nhánh Cực Hỏa Đạo vào thực chiến.","detail":"Trong cảnh tượng giữa tinh không, Tiên Tổ thi triển Bát Cực Tiên Đạo với nhánh Cực Hỏa Đạo, điểm một ngón phóng ra chín vòng tròn khói xanh lần lượt ấn xuống Thiên Ngưu. Tới @c1731, Vương Lâm lần đầu đem Cực Hỏa Đạo vào thực chiến, để một thức thần thông nhờ hỏa mà phát huy được hai đợt công kích.","thuocTinh":"Tiên đạo","uyLuc":"Tạo chín vòng tròn khói xanh để trấn áp Thiên Ngưu trong cảnh tượng ảo giác.","chieuTieuBieu":["Cực Hỏa Đạo"],"nguoiTu":[{"ten":"Tiên Tổ","tuChuong":"@c1730","tangDatToi":"khong-ro","trangThai":"thi triển trong ảo giác"},{"ten":"Vương Lâm","tuChuong":"@c1731","tangDatToi":"Một vòng thanh khí","trangThai":"sơ bộ thi triển"}],"capNhatToi":"@c1730","nguon":["@c1730","@c1731"],"tabs":{"tienTrinh":[{"chuong":"@c1731","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thực chiến","text":"Vương Lâm lần đầu đem Cực Hỏa Đạo vào thực chiến và để một thức thần thông phát huy hai đợt công kích nhờ hỏa bổn nguyên chân thân. Hắn cũng hiểu ra đại giá của chiêu này là hao tổn lực lượng phân thân xác đá.","anchor":"Thần thông này khi có chín vòng thanh khí vờn quanh thì có thể phong ấn Thiên Ngưu, thậm chỉ là phong ấn cả Đại Thiên Tôn!"}]},"congNang":["Tạo vòng thanh khí mang lực phong ấn cực mạnh @c1731","Khi đủ chín vòng có thể phong ấn Thiên Ngưu, thậm chí Đại Thiên Tôn @c1731","Nhờ hỏa mà một thức thần thông phát huy được hai đợt công kích @c1731"],"dacDiem":"Có nhánh Cực Hỏa Đạo, thi triển bằng cách điểm ngón tay phóng ra các vòng tròn khói xanh mang lực phong ấn."},{"id":"cuc-hoa-dao","name":"Cực Hỏa Đạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"khong-ro","hePhai":"Tiên Tổ","soHuu":["Tiên Tổ"],"blurb":"Cực Hỏa Đạo là một đạo trong Bát Cực Tiên Đạo do Tiên Tổ thi triển khi trấn áp Thiên Ngưu. (+) Đạo thuật Tiên Hoàng thi triển cùng Bát Cực Đạo để điều động đầu lâu Tiên Tổ. [CAN-SOAT-GOP]","detail":"Tiên Tổ dùng Cực Hỏa Đạo trong Bát Cực Tiên Đạo, điểm xuống một ngón khiến chín vòng tròn khói xanh lần lượt ấn xuống Thiên Ngưu.","thuocTinh":"Hỏa","nguonGoc":"Một đạo thuộc Bát Cực Tiên Đạo của Tiên Tổ.","uyLuc":"Triển khai chín vòng tròn khói xanh để trấn áp Thiên Ngưu.","nguoiTu":[{"ten":"Tiên Tổ","tuChuong":"@c1730","tangDatToi":"khong-ro","trangThai":"thi triển trong ảo giác"}],"capNhatToi":"@c1730","nguon":["@c1730","@c1890"],"tabs":{}},{"id":"ba-van-sau-ngan-mat-quy","name":"Ba vạn sáu ngàn mặt quỷ","cn":null,"aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Cao thủ Không Kiếp sơ kỳ"],"blurb":"Thần thông của thiếu phụ Đại Hồn Môn, lấy hắc khí từ ba vạn sáu ngàn lỗ chân lông hóa thành đại quân quỷ diện. Chiêu này bị Cực Hỏa Đạo của Vương Lâm phá tan hoàn toàn.","detail":"Khi cảm nhận uy áp từ Cực Hỏa Đạo, thiếu phụ lập tức thúc động thần thông này để ngăn cản. Hắc khí từ khắp lỗ chân lông của nàng ngưng thành vô số mặt quỷ gào thét, nhưng cuối cùng vẫn bị vòng khói thanh khí cuốn nát.","thuocTinh":"Âm sát khí","uyLuc":"Dùng để ngăn cản trực diện đòn đánh của đối thủ","dacDiem":"Hóa hắc khí toàn thân thành ba vạn sáu ngàn quỷ diện","congNang":["Tạo đại quân mặt quỷ từ hắc khí toàn thân để công kích và cản địch @c1731"],"nguoiTu":[{"ten":"Cao thủ Không Kiếp sơ kỳ","tuChuong":"@c1731","tangDatToi":"Đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1731","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu lộ diện","text":"Thiếu phụ Đại Hồn Môn tung ra ba vạn sáu ngàn mặt quỷ để cản Cực Hỏa Đạo nhưng bị phá tan ngay trong lần va chạm đầu tiên.","anchor":"ba vạn sáu ngàn lỗ chân lông liền tuôn ra hắc khí. Đám hắc khí này trong nháy mắt đã bao phủ toàn thân nàng, hóa thành ba vạn sáu ngàn mặt quỷ"}]},"capNhatToi":"@c1731","nguon":["@c1731"]},{"id":"hon-dien-dao","name":"Hồn Diễn Đạo","aliases":["Công pháp Hồn Diễn Đạo","Đạo thuật Hồn Diễn Đạo"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông đạo thuật","phamCap":"Đạo thuật Đại Hồn Môn","hePhai":"Đại Hồn Môn","soHuu":["Thanh Ngưu chân nhân","Đại Hồn Môn"],"blurb":"Hồn Diễn Đạo là thần thông đạo thuật của Đại Hồn Môn, được Thanh Ngưu chân nhân dùng để tính biết Vương Lâm sẽ xuất hiện ở Thiên Sơn. Trọng điểm của thuật không chỉ là tính toán người khác mà còn thay đổi bản thân để khó bị người ngoài suy tính. (+) Thuật suy tính huyền diệu, tạo người tí hon trong lòng bàn tay thổ nạp đồng thời tính toán để tìm ra cơ hội hay phương pháp. Vương Lâm dùng hai mươi ngày suy tính vô số lần để xác định phương pháp dung hợp sát lục lôi đình chân thân. [CAN-SOAT-GOP]","detail":"Hồn Diễn Đạo được Thanh Ngưu chân nhân giới thiệu là thần thông đạo thuật của Đại Hồn Môn, nhờ đó lão biết trước Vương Lâm sẽ tới Thiên Sơn @c1732. Lão giải thích năng lực này chỉ là bước đầu nếu so với Đạo Huyền quốc sư của Tiên Tộc, và điểm then chốt của thuật là khiến bản thân biến đổi để người ngoài khó tính toán được mình.","thuocTinh":"Tính toán, diễn biến bản thân, chống bị suy tính","nguonGoc":"Đại Hồn Môn","congNang":["Tính toán dự đoán hành tung của người khác, như việc Thanh Ngưu chân nhân biết Vương Lâm sẽ xuất hiện ở Thiên Sơn @c1732","Thay đổi bản thân để người khác khó tính toán được mình @c1732"],"nguoiTu":[{"ten":"Thanh Ngưu chân nhân","tuChuong":"@c1732","tangDatToi":"Chưa rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1732","loai":"xuất hiện","importance":"major","giaiDoan":"Thanh Ngưu tiết lộ đạo thuật","text":"Thanh Ngưu chân nhân giới thiệu Hồn Diễn Đạo là thần thông đạo thuật của Đại Hồn Môn, có thể tính toán dự đoán và trọng điểm là thay đổi bản thân để người khác khó suy tính.","anchor":"Đại Hồn Môn của ta có thần thông đạo thuật tên là Hồn Diễn Đạo"}]},"capNhatToi":"@c1732","nguon":["@c1732","@c1934"],"dacDiem":"Điểm then chốt không chỉ ở việc tính toán người khác mà còn khiến bản thân biến đổi để khó bị suy tính."},{"id":"sanh-tu-nghich-dong","name":"Sanh Tử Nghịch Động","cn":"生死逆動","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Vương Lâm"],"blurb":"Sanh Tử Nghịch Động là thần thông thuộc Ma đạo, có khả năng biến sinh cơ trong thân đối phương thành tử khí, đồng thời dẫn động tử khí từ bên ngoài.","detail":"Đây là thần thông Ma đạo do Vương Lâm thi triển. Khi vận dụng, Vương Lâm vươn ngón trỏ điểm một chỉ, khiến sinh cơ trong thân đối phương chuyển hóa thành tử khí, đồng thời dẫn động tử khí khổng lồ từ nơi phong ấn sâu trong lòng đất. Trong lần thi triển ghi nhận, thần thông này đã biến sinh cơ thân Viêm Loan thành tử khí và dẫn động tử khí nơi Thiên Ngưu bị phong ấn, dung hợp hóa thành hình hài Thiên Ngưu trên bầu trời.","tabs":{"tienTrinh":[{"chuong":"@c1734","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển tại Đại Hồn Môn","text":"Vương Lâm dùng Sanh Tử Nghịch Động biến sinh cơ thân Viêm Loan thành tử khí, dẫn động tử khí từ nơi phong ấn Thiên Ngưu dưới lòng đất, hóa hình Thiên Ngưu khổng lồ trên không.","anchor":"Ma đạo, Sanh Tử Nghịch Động"}]},"nguon":["@c1734"],"uyLuc":"Dẫn động tử khí khổng lồ từ nơi Thiên Ngưu bị phong ấn, dung hợp hóa thành hình hài Thiên Ngưu trên bầu trời.","dacDiem":"Thần thông thuộc Ma đạo, thi triển bằng một chỉ điểm,uyển hóa sinh cơ thành tử khí và dẫn động tử khí ngoại lai.","congNang":["Biến sinh cơ trong thân đối phương thành tử khí @c1734","Dẫn động tử khí khổng lồ từ nơi phong ấn sâu trong lòng đất @c1734","Dung hợp tử khí dẫn động được hóa thành hình hài (hình hài Thiên Ngưu trên bầu trời) @c1734"]},{"id":"co-dao-vo-tien","name":"Cổ đạo vô tiên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông của Vương Lâm tạo chín tầng sóng gợn, trong chương này bị thần thức Không Kiếp hậu kỳ của Thanh Ngưu chân nhân phá tan.","detail":"Khi Thanh Ngưu chân nhân hiện thân, chín tầng sóng gợn Cổ đạo vô tiên của Vương Lâm lần lượt sụp đổ trong tích tắc, hóa thành ánh sáng tiêu tán, cho thấy thần thông này bị áp chế trước thần thức của cao thủ Không Kiếp hậu kỳ.","uyLuc":"Bị thần thức Thanh Ngưu chân nhân phá sụp trong tích tắc.","dacDiem":"Biểu hiện thành chín tầng sóng gợn.","congNang":["Tạo nhiều tầng sóng gợn công kích hoặc ngăn cản đối thủ, nhưng có thể bị thần thức vượt trội phá vỡ @c1735"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1735","tangDatToi":"Chín tầng sóng gợn","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1735","loai":"thi triển","importance":"normal","giaiDoan":"Bị phá bởi Thanh Ngưu chân nhân","text":"Chín tầng sóng gợn do Vương Lâm thi triển bị thần thức Thanh Ngưu chân nhân phá sụp trong tích tắc.","anchor":"Chín tầng sóng gợn liền lần lượt sụp đổ, trong tích tắc liền biến mất, hóa thành một vùng ánh sáng tiêu tán"}]},"capNhatToi":"@c1735","nguon":["@c1735"]},{"id":"mi-cong","name":"Mị công","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Phàn San Mộng"],"blurb":"Công pháp mị hoặc được Viêm Loan nhắc tới khi ép Phàn San Mộng tiếp cận Vương Lâm.","detail":"Viêm Loan cho rằng Phàn San Mộng có thể dựa vào mị công và sắc đẹp để tiếp cận Vương Lâm, đồng thời dùng năng lực này làm phương tiện thực hiện ý đồ khắc chết hắn.","thuocTinh":"Mị hoặc","uyLuc":"Được Viêm Loan xem là bản lãnh Phàn San Mộng am hiểu để đối phó nam tu sĩ.","dacDiem":"Gắn với vẻ đẹp và khả năng mê hoặc đối tượng.","congNang":["Mị hoặc nam tu sĩ khi kết hợp với sắc đẹp của người tu @c1735"],"nguoiTu":[{"ten":"Phàn San Mộng","tuChuong":"@c1735","tangDatToi":"Không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1735","loai":"nhắc tới","importance":"normal","giaiDoan":"Viêm Loan ép Phàn San Mộng sử dụng","text":"Viêm Loan ép Phàn San Mộng dựa vào mị công và vẻ đẹp để tiếp cận Vương Lâm.","anchor":"Bằng vào mị công và vẻ đẹp của ngươi, ngươi chỉ có thể làm thôi"}]},"capNhatToi":"@c1735","nguon":["@c1735"]},{"id":"trong-huyen-thuat","name":"Trọng Huyễn Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đại Hồn Môn","soHuu":[],"blurb":"Một trong những thuật pháp Vương Lâm muốn tìm trong Tàng Hồn Các.","detail":"Trọng Huyễn Thuật được nhắc như mục tiêu tìm kiếm của Vương Lâm khi hắn đi qua các tầng đầu Tàng Hồn Các. Chương này chưa nêu công năng cụ thể của thuật này.","nguon":["@c1737"]},{"id":"thuat-trieu-hoi-hon-phach-tien-to","name":"Thuật triệu hồi hồn phách Tiên Tổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Đại Hồn Môn","soHuu":[],"blurb":"Thuật pháp liên quan tới việc triệu hồi hồn phách Tiên Tổ, được Vương Lâm tìm kiếm trong Tàng Hồn Các.","detail":"Thuật triệu hồi hồn phách Tiên Tổ được nêu cùng Trọng Huyễn Thuật như thứ Vương Lâm muốn tìm. Các hồn thể từ tầng một tới tầng năm Tàng Hồn Các vẫn chưa phải mục tiêu của hắn.","nguon":["@c1737"]},{"id":"dan-hon-thuat","name":"Dẫn Hồn thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cấp Không Kiếp, bản tầng sáu chưa đầy đủ","hePhai":"Đại Hồn Môn","soHuu":["Đại Hồn Môn"],"blurb":"Thần thông dẫn hồn mà Vương Lâm muốn tìm trong Tàng Hồn Các. Ở tầng sáu chỉ lộ bản chưa đầy đủ, cần lên tầng bảy mới có thêm.","detail":"Dẫn Hồn thuật nằm trong hồn thể phía trên đỉnh đầu Viêm Loan ở tầng sáu Tàng Hồn Các. Vương Lâm xác nhận bản tại tầng sáu không đầy đủ, tương tự Đa Trọng Huyễn Thuật, nên bản cao hơn phải ở tầng bảy trở lên.","thuocTinh":"Hồn thuật","uyLuc":"Có tác dụng dẫn hồn, nhưng chương này chỉ xác nhận bản tầng sáu chưa đầy đủ.","dacDiem":"Được lưu trong hồn thể công pháp của tầng sáu Tàng Hồn Các.","congNang":["Dẫn hồn, bản tầng sáu chưa đầy đủ @c1738"],"nguoiTu":[],"tabs":{"tienTrinh":[{"chuong":"@c1738","loai":"xuất hiện","importance":"normal","giaiDoan":"Bản tầng sáu","text":"Vương Lâm tìm thấy Dẫn Hồn thuật trong hồn thể ở tầng sáu nhưng xác nhận bản này chưa đầy đủ.","anchor":"Dẫn Hồn thuật này cũng không đầy đủ. Chẳng lẽ ở tầng bảy mới có thêm?"}]},"capNhatToi":"@c1738","nguon":["@c1738"]},{"id":"hon-dien-quy-dao-thuat","name":"Hồn Diễn Quy Đạo Thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thuật linh hồn","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Vương Lâm","Viêm Loan"],"blurb":"Hồn Diễn Quy Đạo Thuật là một thuật linh hồn được Vương Lâm tìm thấy ở dạng tương đối đầy đủ trong hồn thể tầng bảy Tàng Hồn Các. Vương Lâm sau đó chọn hồn thể thứ bảy tầng tám Tàng Hồn Các và dùng ba ngày hấp thu trọn công pháp này.","detail":"Hồn Diễn Quy Đạo Thuật có nguồn gốc từ hồn thể tầng bảy Tàng Hồn Các, nơi Vương Lâm tìm được nó ở trạng thái tương đối đầy đủ (@c1740). Theo lời hé lộ, nếu kết hợp với hồ lô màu tím của La Vân Hải, người tu thuật này có thể gọi đệ cửu Tiên Tổ giáng xuống. Vương Lâm về sau chọn hồn thể thứ bảy tầng tám Tàng Hồn Các và dùng ba ngày hấp thu trọn Hồn Diễn Quy Đạo Thuật (@c1742). Cốt lõi của thuật là phân hóa một phần tàn hồn của bản thân làm vật câu thông với thiên địa để thi triển thần thông.","thuocTinh":"Linh hồn","nguonGoc":"Hồn thể tầng bảy Tàng Hồn Các","congNang":["Kết hợp hồ lô màu tím của La Vân Hải có thể gọi đệ cửu Tiên Tổ giáng xuống @c1740","Phân hóa một phần tàn hồn của bản thân làm vật câu thông với thiên địa để thi triển thần thông @c1742"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1740","tangDatToi":"bản đầy đủ trong hồn thể thứ bảy tầng tám","trangThai":"đã hấp thu"}],"tabs":{"tienTrinh":[{"chuong":"@c1740","loai":"xuất hiện","importance":"normal","giaiDoan":"Bản tương đối đầy đủ ở tầng bảy","text":"Vương Lâm tìm được Hồn Diễn Quy Đạo Thuật tương đối đầy đủ trong tầng bảy Tàng Hồn Các, đồng thời biết thuật này có thể phối hợp hồ lô tím để gọi đệ cửu Tiên Tổ giáng xuống.","anchor":"Ngươi có vật này, tu luyện Hồn Diễn Quy Đạo Thuật có thể gọi đệ cửu Tiên Tổ giáng xuống!"},{"chuong":"@c1742","loai":"xuất hiện","importance":"major","giaiDoan":"bản đầy đủ tầng tám","text":"Vương Lâm chọn hồn thể thứ bảy tầng tám Tàng Hồn Các và dùng ba ngày hấp thu trọn Hồn Diễn Quy Đạo Thuật, khiến khẩu quyết dung nhập linh hồn như bản năng.","anchor":"toàn bộ tinh lực đều đặt vào việc hấp thu Hồn Diễn Quy Đạo Thuật ẩn chứa trong cơ thể hồn thể thứ bảy kia"}]},"capNhatToi":"@c1740","nguon":["@c1740","@c1742"],"uyLuc":"Khi kết hợp với hồ lô màu tím của La Vân Hải, có thể gọi đệ cửu Tiên Tổ giáng xuống @c1740","dacDiem":"Thuật linh hồn, lấy việc phân hóa một phần tàn hồn của bản thân làm vật câu thông với thiên địa để thi triển thần thông"},{"id":"khi-the-phan-than-cua-vuong-lam","name":"Khí thế phân thân của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông/khí thế","phamCap":"Không rõ","hePhai":"Liên quan phân thân của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Khí thế từ phân thân của Vương Lâm, lần đầu được hắn hoàn toàn điều động để trấn áp Viêm Loan.","detail":"Khí thế này mang cảm giác vô cùng giống Cổ Tổ, mạnh tới mức chính Vương Lâm cũng kinh hãi. Khi thi triển, nó có thể trấn áp tâm thần đối phương và lưu khe hở sợ hãi trong đạo tâm mà không phá hủy đạo niệm tu hành.","thuocTinh":"Khí thế trấn áp tâm thần","uyLuc":"Có thể khiến Viêm Loan sinh sợ hãi chưa từng có và buộc phải buông vật cược.","dacDiem":"Khí tức giống Cổ Tổ, người ngoài nếu không biết nguồn gốc sẽ khó nhận ra là do phân thân của Vương Lâm tạo thành.","congNang":["Trấn áp tâm thần đối phương khi Vương Lâm hoàn toàn điều động khí thế phân thân @c1741","Lưu khe hở sợ hãi trong đạo tâm đối phương mà không trực tiếp phá đạo niệm @c1741"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1741","tangDatToi":"Hoàn toàn điều động khí thế phân thân","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1741","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu hoàn toàn điều động","text":"Vương Lâm lần đầu hoàn toàn điều động khí thế phân thân để trấn áp Viêm Loan, khiến nàng sinh sợ hãi và phải buông hồ lô.","anchor":"Đây là lần đầu tiên hắn hoàn toàn điều động khí thế của phân thân, dùng để trấn áp đối phương."}]},"capNhatToi":"@c1741","nguon":["@c1741"]},{"id":"chin-than-thong-dai-hon-mon","name":"Chín thần thông Đại Hồn Môn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông trấn phái","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Đại Hồn Môn"],"blurb":"Chín loại thần thông cực mạnh của Đại Hồn Môn, ẩn trong chín hồn thể tại tầng tám Tàng Hồn Các.","detail":"Chúng được cất giữ ở tầng tám Tàng Hồn Các, mỗi thần thông đều nằm trong một hồn thể lơ lửng và được mô tả có uy lực hủy thiên diệt địa. Vương Lâm tiến vào tầng tám để chuẩn bị lựa chọn thần thông công pháp từ đây.","nguonGoc":"Đại Hồn Môn, tầng tám Tàng Hồn Các","uyLuc":"Mỗi loại đều được mô tả có thể hủy thiên diệt địa.","dacDiem":"Ẩn chứa trong chín hồn thể tỏa ánh sáng nhu hòa.","congNang":["Truyền thừa chín loại thần thông cực mạnh của Đại Hồn Môn @c1741"],"tabs":{"tienTrinh":[{"chuong":"@c1741","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ tại tầng tám","text":"Sau khi vào tầng tám Tàng Hồn Các, Vương Lâm phát hiện chín hồn thể ẩn chứa chín thần thông cực mạnh của Đại Hồn Môn.","anchor":"ẩn chứa chín loại thần thông cực kỳ mạnh mẽ của Đại Hồn Môn"}]},"capNhatToi":"@c1741","nguon":["@c1741"]},{"id":"da-trong-huyen-thuat","name":"Đa Trọng Huyễn Thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Huyễn thuật","phamCap":"cửu trọng là hoàn chỉnh","hePhai":"Đại Hồn Môn","soHuu":["Vương Lâm"],"blurb":"Huyễn thuật làm nên danh tiếng Hồn Huyễn của Đại Hồn Môn. Tầng tám Tàng Hồn Các chỉ có bản tới bát trọng, còn cửu trọng hoàn chỉnh ở tầng chín.","detail":"Đa Trọng Huyễn Thuật là căn cơ tạo nên danh tiếng Hồn Huyễn của Đại Hồn Môn. Đa số đệ tử trọng yếu chỉ thi triển được tam tứ trọng; từ bát trọng trở lên uy lực đạt mức kinh thiên động địa. Hồn thể thứ ba tầng tám Tàng Hồn Các chỉ chứa tới bát trọng, còn bản cửu trọng hoàn chỉnh nằm ở tầng chín; Vương Lâm từng ở động phủ giới không nghiên cứu thấu, chỉ nhờ tấm buồm mặt quỷ mới thi triển được.","thuocTinh":"huyễn thuật","nguonGoc":"Đại Hồn Môn","uyLuc":"Từ bát trọng trở lên có uy lực kinh thiên động địa.","dacDiem":"Cần phân hóa tàn hồn câu thông thiên địa theo cơ chế chung được Vương Lâm ngộ ra.","congNang":["Thi triển nhiều tầng ảo thuật, từ bát trọng trở lên uy lực kinh thiên động địa @c1742"],"cacTang":[{"ten":"bát trọng","moTa":"Tầng tám Tàng Hồn Các chứa bản tới bát trọng.","chuong":"@c1742"},{"ten":"cửu trọng","moTa":"Bản hoàn chỉnh nằm ở tầng chín Tàng Hồn Các, là thứ Vương Lâm cho rằng bắt buộc phải có.","chuong":"@c1742"}],"tabs":{"tienTrinh":[{"chuong":"@c1742","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"bát trọng và cửu trọng","text":"Chương hé lộ hệ tầng của Đa Trọng Huyễn Thuật: tầng tám Tàng Hồn Các chỉ có tới bát trọng, còn cửu trọng hoàn chỉnh ở tầng chín.","anchor":"Một khi đạt đến bát trọng ảo thuật trở lên, uy lực của nó sẽ tới mức kinh thiên động địa"}]},"capNhatToi":"@c1742","nguon":["@c1742"]},{"id":"dao-dien-hon","name":"Đạo Diễn Hồn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"truyền thừa cổ","hePhai":"môn phái ẩn trên Tiên Cương đại lục","soHuu":[],"blurb":"Bộ truyền thừa song sinh được nhắc cùng Hồn Diễn Đạo. Chương chỉ hé lộ qua lời kể của Thanh Ngưu lão tổ, chưa có người thi triển.","detail":"Theo lời đồn trong Đại Hồn Môn, Hồn Diễn Đạo Thuật vốn có hai bộ, trong đó một bộ là Đạo Diễn Hồn. Bộ này do đệ tử còn lại của môn phái cực mạnh ẩn trên Tiên Cương đại lục truyền thừa, song chương chưa xác nhận người tu hiện tại hay công năng cụ thể.","nguonGoc":"môn phái cực mạnh ẩn trên Tiên Cương đại lục","dacDiem":"Được đặt cạnh Hồn Diễn Đạo như một bộ truyền thừa song sinh, nhưng chưa được thi triển trong chương.","tabs":{"tienTrinh":[{"chuong":"@c1742","loai":"nhắc tới","importance":"normal","giaiDoan":"truyền thừa song sinh","text":"Thanh Ngưu lão tổ nhắc lời đồn rằng Hồn Diễn Đạo Thuật vốn có hai bộ, một bộ là Đạo Diễn Hồn do đồng môn của lão tổ đời đầu truyền thừa.","anchor":"vốn có hai bộ, trong đó một bộ tên là Đạo Diễn Hồn!"}]},"capNhatToi":"@c1742","nguon":["@c1742"]},{"id":"dao-dien-thuat","name":"Đạo Diễn Thuật","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Sở học","phamCap":"không rõ","hePhai":"Huyền Đạo nhất mạch","soHuu":["Quốc sư"],"blurb":"Sở học của Huyền Đạo nhất mạch thuộc quốc sư ở hoàng thành Trung Châu. Tên gọi gợi liên hệ với Hồn Diễn Đạo và Đạo Diễn Hồn nhưng chương chưa khẳng định quan hệ.","detail":"Đạo Diễn Thuật được nhắc qua lời đồn đáng sợ nhất do các đời đệ tử Đại Hồn Môn sưu tập tin tức và sửa lại. Sở học này thuộc Huyền Đạo nhất mạch của quốc sư tại hoàng thành Trung Châu, khiến Thanh Ngưu chân nhân bất an nhìn về Trung Châu; chương chưa xác nhận nó đồng nhất với Đạo Diễn Hồn hay Hồn Diễn Đạo.","nguonGoc":"Huyền Đạo nhất mạch của quốc sư tại hoàng thành Trung Châu","dacDiem":"Chỉ mới lộ tên qua lời đồn, chưa có cảnh thi triển.","tabs":{"tienTrinh":[{"chuong":"@c1742","loai":"nhắc tới","importance":"normal","giaiDoan":"lời đồn Trung Châu","text":"Thanh Ngưu lão tổ nhắc lời đồn rằng Huyền Đạo nhất mạch của quốc sư ở hoàng thành Trung Châu có sở học tên Đạo Diễn Thuật.","anchor":"Huyền Đạo nhất mạch của quốc sư có sở học tên là Đạo Diễn Thuật"}]},"capNhatToi":"@c1742","nguon":["@c1742"]},{"id":"con-duong-tu-luyen-bon-nguyen-cua-vuong-lam","name":"Con đường tu luyện bổn nguyên của Vương Lâm","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Thể hệ tu luyện","phamCap":"không rõ","hePhai":"Bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Cơ chế tu luyện đặc thù của Vương Lâm trên Tiên Cương, không dựa Hương Hỏa mà dựa cảm ngộ và hấp thu vật chất Thiên Địa để hoàn thiện bổn nguyên.","detail":"Chương này nêu rõ then chốt tu đạo của Vương Lâm nằm ở bổn nguyên: bảy bổn nguyên hiện có khiến hắn dừng ở Không Linh hậu kỳ, thủy bổn nguyên đại thành sẽ thành tám đạo và đạt Không Linh Đại viên mãn, đủ chín đạo bổn nguyên sẽ bước vào Không Huyền. Con đường này khác người thường vì không có Hương Hỏa, nhưng nếu thành tựu sẽ giúp hắn khi vào Không Huyền có thể chiến Không Kiếp sơ kỳ, tới Không Huyền hậu kỳ còn có khả năng một lần vượt liền cửu Huyền Kiếp.","thuocTinh":"bổn nguyên","yeuCau":"Cảm ngộ và hấp thu vật chất Thiên Địa để hoàn thiện chín đạo bổn nguyên.","uyLuc":"Đủ chín đạo bổn nguyên có thể tiến nhập Không Huyền, đồng thời chiến lực vượt xa tu sĩ cùng cảnh theo lời tự tính của Vương Lâm.","dacDiem":"Không dùng Hương Hỏa, then chốt nằm ở đại thành bổn nguyên.","congNang":["Tám đạo bổn nguyên giúp đạt Không Linh Đại viên mãn @c1743","Chín đạo bổn nguyên giúp tiến nhập Không Huyền @c1743"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1743","tangDatToi":"bảy bổn nguyên, đang hướng tới thủy bổn nguyên đại thành","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1743","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Minh định lộ trình bổn nguyên","text":"Vương Lâm xác định con đường của mình là dùng bổn nguyên làm then chốt, từ bảy đạo hiện có hướng tới tám đạo rồi chín đạo để phá Không Huyền.","anchor":"Có thể nói, then chốt trong việc tu đạo của Vương đều nằm ở bổn nguyên!"}]},"capNhatToi":"@c1743","nguon":["@c1743"]},{"id":"thuy-bon-nguyen","name":"Thủy bổn nguyên","cn":"","loai":"khac","loaiLabel":"Bổn nguyên","phamCap":"Thực bổn nguyên","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thủy bổn nguyên là bổn nguyên thuộc tính nước mà Vương Lâm dung hợp trong lần bế quan tại Đại Hồn Môn. Nó cần trải qua chu kỳ ngưng–tán để hòa vào cơ thể, nhưng vòng cuối thiếu một lượng nước lớn.","detail":"Giọt thủy bổn nguyên được đặt lên mi tâm Vương Lâm để dung hợp với thủy bổn nguyên tiểu thành vốn có trong cơ thể hắn. Mỗi vòng tuần hoàn gồm pha ngưng hút cạn nước và máu khiến thân thể hóa thây khô trong chín ngày, rồi pha tán khiến thân thể hồi phục trong chín ngày. Sau tám vòng, giọt nước gần tiêu tán; đến vòng thứ chín thì không đủ hoàn thành, khiến Vương Lâm cần lượng nước lớn để viên mãn.","thuocTinh":"Thủy","uyLuc":"Nếu hoàn thành chín vòng tuần hoàn thì thủy bổn nguyên viên mãn và tu vi của Vương Lâm lập tức gia tăng.","dacDiem":"Thực bổn nguyên phải dung hợp và cắn nuốt ý chí; khi ngưng có thể khiến thân thể người tu hóa thành thây khô.","congNang":["Dung hợp vào cơ thể người tu để khiến thủy bổn nguyên tiến tới viên mãn @c1744","Hoàn tất chín vòng tuần hoàn có thể làm tu vi người tu gia tăng @c1744"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1744","tangDatToi":"8/9 vòng tuần hoàn, chưa viên mãn","trangThai":"đang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1744","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Dung hợp chín vòng tuần hoàn","text":"Vương Lâm dùng giọt thủy bổn nguyên để dung hợp theo chu kỳ ngưng–tán, hoàn thành tám vòng nhưng thất bại ở vòng thứ chín vì không đủ thủy bổn nguyên.","anchor":"Thủy bổn nguyên không đủ hoàn thành một lần tuần hoàn cuối cùng. Còn thiếu một lần! Ta cần một lượng nước lớn!"}]},"trangThai":"Chưa viên mãn trong cơ thể Vương Lâm","capNhatToi":"@c1744","nguon":["@c1744"]},{"id":"thuy-bon-nguyen-tuan-hoan-thu-chin","name":"Thủy bổn nguyên tuần hoàn thứ chín","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Bổn nguyên tu luyện","phamCap":"không rõ","hePhai":"Thủy bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Giai đoạn tu luyện thủy bổn nguyên của Vương Lâm, cần lượng lớn nước để hoàn thành lần tuần hoàn thứ chín. Việc thiếu thủy bổn nguyên khiến thân thể hắn khô héo và trở thành tai họa ngầm.","detail":"Viêm Loan nhận ra trạng thái của Vương Lâm không phải do luyện công pháp quỷ dị mà do đang hấp thu thủy bổn nguyên. Vương Lâm cần tìm vùng biển rộng để hấp thu lượng lớn thủy bổn nguyên, hoàn thành tuần hoàn thứ chín và xử lý nguy cơ của thân thể.","dinhDanh":"goc","thuocTinh":"Thủy bổn nguyên","congNang":["Bổ sung lượng lớn thủy bổn nguyên để khôi phục thân thể khô héo và hoàn thành tuần hoàn thứ chín @c1745"],"yeuCau":"Cần nơi có lượng nước cực lớn như vùng biển vô biên giữa Thiên Ngưu Châu và Lục Ma Châu.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1745","tangDatToi":"đang hướng tới tuần hoàn thứ chín","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1745","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Cần lượng lớn thủy bổn nguyên","text":"Viêm Loan nhận ra Vương Lâm đang hấp thu thủy bổn nguyên, còn Vương Lâm rời Đại Hồn Môn để tìm nơi có nhiều nước nhằm hoàn thành tuần hoàn thứ chín.","anchor":"hấp thu một lượng lớn thủy bổn nguyên, hoàn thành lần tuần hoàn thứ chín"}]},"capNhatToi":"@c1745","nguon":["@c1745"]},{"id":"tho-don-thuat","name":"Thổ độn thuật","cn":"","aliases":[],"loai":"khac","loaiLabel":"Độn thuật","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Tu sĩ thổ độn phục kích Vương Lâm trên Cực Thiên thảo nguyên"],"blurb":"Độn thuật cho phép tu sĩ ẩn vào lòng đất và di chuyển bỏ chạy. Trong chương này, kẻ phục kích dùng thuật này trên Cực Thiên thảo nguyên nhưng vẫn bị truy sát.","detail":"Tu sĩ phục kích Vương Lâm dùng thổ độn thuật để dung nhập mặt đất và nhanh chóng bỏ trốn, đồng thời cố dẫn họa về phía các động phủ tán tu. Thuật này không giúp hắn thoát khỏi địa khí hút sinh cơ của Vương Lâm và sự chặn đường của Tả Trâu.","congNang":["Ẩn thân và bỏ chạy trong lòng đất @c1746"],"nguoiTu":[{"ten":"Tu sĩ thổ độn phục kích Vương Lâm trên Cực Thiên thảo nguyên","tuChuong":"@c1746","tangDatToi":"không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1746","loai":"thi triển","importance":"normal","giaiDoan":"Phục kích Cực Thiên thảo nguyên","text":"Tu sĩ phục kích dùng thổ độn thuật để ẩn vào lòng đất và bỏ chạy sau khi công kích Vương Lâm thất bại.","anchor":"thân ảnh kia đang dùng thổ độn thuật nhanh chóng bỏ trốn"}]},"capNhatToi":"@c1746","nguon":["@c1746"]},{"id":"dia-khi-hut-sinh-co-cua-vuong-lam","name":"Địa khí hút sinh cơ của Vương Lâm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đạo pháp hấp thu","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đạo pháp Vương Lâm dùng bằng cách ấn tay xuống đất, dẫn địa khí bộc phát để hút hơi nước và sinh cơ từ thảo nguyên. Luồng héo rũ lan đi như truy sát kẻ đang dùng thổ độn.","detail":"Khi kẻ phục kích bỏ chạy trong lòng đất, Vương Lâm không lập tức đuổi theo mà ấn hai tay xuống mặt đất. Địa khí từ cơ thể hắn bộc phát khiến cỏ xanh nhanh chóng héo rũ, hơi nước tụ vào thân thể hắn và lan theo hướng kẻ thổ độn bỏ chạy.","congNang":["Hút hơi nước và sinh cơ qua mặt đất, khiến thảo nguyên héo rũ @c1746"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1746","tangDatToi":"đã thi triển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1746","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát trên Cực Thiên thảo nguyên","text":"Vương Lâm ấn tay xuống đất, dẫn địa khí hút hơi nước và sinh cơ của thảo nguyên để truy sát tu sĩ thổ độn.","anchor":"Một cái nhấn này khiến một luồng địa khí từ trong người Vương Lâm bộc phát ra"}]},"capNhatToi":"@c1746","nguon":["@c1746"]},{"id":"cam-che-phong-an-dan-hai","name":"Cấm chế phong ấn Đan Hải","cn":"","aliases":["Cấm chế đại trận Đan Hải","Đại trận cấm chế bao phủ Đan Hải","Trận pháp cấm chế Đan Hải của Lục Ma Châu","Trận pháp cấm chế vô hình bao phủ Đan Hải","Cấm chế đại trận trên Đan Hải"],"loai":"khac","loaiLabel":"Cấm chế trận pháp","phamCap":"không rõ","hePhai":"không rõ","soHuu":[],"blurb":"Tầng cấm chế vô hình bao phủ toàn bộ Đan Hải, cho phép đi vào nhưng không thể đi ra. Vương Lâm chỉ hơi phát hiện ra nó khi hấp thu Thủy bổn nguyên dưới đáy biển.","detail":"Cấm chế này phong tỏa cả Đan Hải như một lớp vô hình cực kỳ huyền diệu. Trong lúc vùng biển bị phong tỏa, bên trong đang diễn ra sát kiếp giữa tu sĩ lục bào quỷ hỏa và tán tu Thiên Ngưu Châu.","congNang":["Phong tỏa Đan Hải, cho vào nhưng không cho ra @c1746"],"tabs":{"tienTrinh":[{"chuong":"@c1746","loai":"xuất hiện","importance":"major","giaiDoan":"Kinh biến Đan Hải","text":"Cấm chế vô hình bao phủ toàn bộ Đan Hải, khiến vùng biển bị phong ấn giữa lúc bên trong phát sinh sát kiếp.","anchor":"Tầng cấm chế này có thể tiến vào nhưng không thể đi ra"}]},"capNhatToi":"@c1746","nguon":["@c1746"]},{"id":"than-thong-quay-nhieu-bien-hoa-thien-dia-cua-ba-lao-to","name":"Thần thông quấy nhiễu biến hóa thiên địa của ba lão tổ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lục Ma Châu","soHuu":["Lão tổ Lục Ma Châu"],"blurb":"Thần thông do ba vị lão tổ Lục Ma Châu triển khai để quấy nhiễu biến hóa thiên địa. Nhờ vậy Thiên Ngưu Châu khó phát hiện biến cố trong Đan Hải.","detail":"Trong chiến dịch Đan Hải, ba vị lão tổ Lục Ma Châu dùng thần thông này để che giấu thiên cơ và hỗ trợ kế hoạch xâm nhập. Nó không trực tiếp là chiêu công kích trong chương, nhưng giữ vai trò chiến lược khi làm mờ biến hóa thiên địa liên quan cuộc đồ sát.","congNang":["Quấy nhiễu biến hóa thiên địa để che giấu hành động xâm nhập Đan Hải @c1747"],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c1747","loai":"nhắc tới","importance":"normal","giaiDoan":"Che giấu chiến dịch Đan Hải","text":"Ba vị lão tổ triển khai thần thông quấy nhiễu biến hóa thiên địa để Thiên Ngưu Châu khó phát hiện biến cố ở Đan Hải.","anchor":"ba vị lão tổ đã triển khai thần thông quấy nhiễu biến hóa của thiên địa"}]},"nguon":["@c1747"]},{"id":"cong-phap-man-cam-mau-tanh-cua-thanh-nien-mat-trang","name":"Công pháp mẫn cảm máu tanh của thanh niên mặt trắng","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Thanh niên mặt trắng"],"blurb":"Công pháp giúp thanh niên mặt trắng cảm nhận khí tức máu tanh vô hình quanh Vương Lâm.","detail":"Khi đối diện Vương Lâm trong Đan Hải, thanh niên mặt trắng nhờ công pháp này nhìn ra sát khí và mấy ngàn oan hồn tu sĩ Lục Ma Châu quanh đối phương, từ đó lập tức lựa chọn bỏ chạy.","thuocTinh":"máu tanh","congNang":["Nhận biết khí tức máu tanh và oan hồn quanh mục tiêu @c1750"],"nguoiTu":[{"ten":"Thanh niên mặt trắng","tuChuong":"@c1750","tangDatToi":"không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1750","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhận ra sát khí","text":"Thanh niên mặt trắng dùng công pháp mẫn cảm máu tanh để phát hiện sát khí và oan hồn quanh Vương Lâm.","anchor":"tu luyện công pháp đối với máu tanh cực kỳ mẫn cảm"}]},"capNhatToi":"@c1750","nguon":["@c1750"]},{"id":"cam-che-dai-tran-dan-hai","name":"Cấm chế đại trận Đan Hải","aliases":["Trận pháp cấm chế Đan Hải của Lục Ma Châu","Trận pháp cấm chế vô hình bao phủ Đan Hải","Cấm chế đại trận trên Đan Hải"],"cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Lục Ma Châu"],"blurb":"Trận pháp phong tỏa Đan Hải do Lục Ma Châu vận hành trong kế hoạch tấn công Thiên Ngưu Châu.","detail":"Thanh niên mặt trắng có thể dung nhập trận pháp để na di, nữ tử cầm la bàn tin Vương Lâm không thoát khỏi trận, còn cuối chương Vương Lâm chuẩn bị kiểm tra lực phong ấn của nó.","congNang":["Phong tỏa Đan Hải và khiến người trong trận khó thoát @c1750","Cho phép tu sĩ Lục Ma Châu dung nhập trận pháp để na di @c1750"],"tabs":{"tienTrinh":[{"chuong":"@c1750","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong tỏa Đan Hải","text":"Trận pháp Đan Hải được nữ tử cầm la bàn tin là có thể giữ Vương Lâm lại trong phạm vi phong tỏa.","anchor":"Hắn ở trong trận pháp này trốn không thoát đâu"}]},"capNhatToi":"@c1750","nguon":["@c1750"]},{"id":"suu-than","name":"Sưu thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Thần thông tra xét ký ức hoặc tình hình từ Nguyên Thần mục tiêu.","detail":"Vương Lâm dùng Sưu thần lên Nguyên Thần tu sĩ họ Tiền để tìm hiểu tình hình trong Đan Hải trước khi phong ấn Nguyên Thần này.","congNang":["Tra xét ký ức hoặc thông tin từ Nguyên Thần mục tiêu @c1750"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1750","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1750","loai":"thi triển","importance":"normal","giaiDoan":"Tra xét Nguyên Thần","text":"Vương Lâm thi triển Sưu thần lên Nguyên Thần tu sĩ họ Tiền rồi phong ấn lại để dùng tiếp.","anchor":"Vương Lâm đối với tu sĩ họ Tiền triển khai thần thông sưu thần"}]},"capNhatToi":"@c1750","nguon":["@c1750"]},{"id":"hu-anh-hai-dong-tu-khong-lo","name":"Hư ảnh hai đồng tử khổng lồ","cn":"","loai":"than-thong","loaiLabel":"Thần thông cấm chế","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Hư ảnh hai đồng tử khổng lồ là thủ đoạn Vương Lâm triệu ra khi tính toán khe hở của cấm chế Đan Hải.","detail":"Phía sau Vương Lâm hiện ra hai đồng tử hư ảo đầy tơ máu, phối hợp với hắn suy tính điểm mỏng trong bảy tầng sương mù để mở đường phá trận.","thuocTinh":"cấm chế","congNang":["Hỗ trợ Vương Lâm tính toán khe hở và điểm mỏng trong đại trận cấm chế Đan Hải."],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1751","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1751","loai":"thi triển","importance":"normal","giaiDoan":"Phá cấm Đan Hải","text":"Vương Lâm triệu hư ảnh hai đồng tử khổng lồ để tính toán cách phá bảy tầng sương mù cấm chế.","anchor":"Phía sau hắn bất ngờ xuất hiện hư ảnh của hai đồng tử khổng lồ."}]},"capNhatToi":"@c1751","nguon":["@c1751"]},{"id":"to-cam-che-huyet-sac","name":"Tơ cấm chế huyết sắc","cn":"","loai":"than-thong","loaiLabel":"Thủ đoạn cấm chế","phamCap":"không rõ","hePhai":"Cấm chế","soHuu":["Vương Lâm"],"blurb":"Tơ cấm chế huyết sắc là các sợi tơ máu Vương Lâm dùng để mở lỗ hổng trong sương mù cấm chế Đan Hải.","detail":"Các sợi tơ máu từ hư ảnh đồng tử khổng lồ bay vào khe hở sương mù, đan thành vòng tròn để tạo lối thông qua từng tầng cấm chế.","thuocTinh":"cấm chế huyết sắc","congNang":["Đan thành vòng tròn tại điểm mỏng của sương mù cấm chế để mở lỗ hổng cho người đi qua."],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1751","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1751","loai":"thi triển","importance":"normal","giaiDoan":"Mở lối qua cấm chế","text":"Vương Lâm dùng tơ cấm chế huyết sắc nối vào các tầng sương mù để mở lỗ hổng vượt trận.","anchor":"Mỗi một chỉ hạ xuống đều có một đạo tơ máu từ trong đồng tử khổng lồ phía sau lan ra"}]},"capNhatToi":"@c1751","nguon":["@c1751"]},{"id":"kiem-dao-cua-van-khong","name":"Kiếm đạo của Vân Không","cn":"","loai":"kiem-quyet","loaiLabel":"Kiếm đạo","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Vân Không"],"blurb":"Kiếm đạo của Vân Không là lối tu cực đoan chỉ tu kiếm, không tu ý cảnh thiên địa.","detail":"Kiếm đạo này thể hiện qua kiếm ảnh từ đáy Đan Hải, một kiếm phân đôi nước biển, phá bốn tầng cấm chế và khiến nhóm Bạch Hổ chấn động.","thuocTinh":"kiếm ý","uyLuc":"Một kiếm phá hủy bốn tầng cấm chế Đan Hải.","dacDiem":"Cả đời không tu ý cảnh thiên địa mà chỉ tu kiếm.","congNang":["Tạo kiếm ảnh khổng lồ chém từ đáy biển lên, phân đôi nước biển và phá tầng cấm chế."],"nguoiTu":[{"ten":"Vân Không","tuChuong":"@c1751","tangDatToi":"không rõ","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1751","loai":"thi triển","importance":"normal","giaiDoan":"Kiếm ảnh Đan Hải","text":"Kiếm đạo của Vân Không bộc phát thành kiếm ảnh từ đáy biển, chém tách Đan Hải và phá nhiều tầng cấm chế.","anchor":"Đây là kiếm đạo! Cả đời không tu Ý Cảnh thiên địa, chỉ tu kiếm"}]},"capNhatToi":"@c1751","nguon":["@c1751"]},{"id":"kiem-y-phan-than-cua-van-khong","name":"Kiếm ý phân thân của Vân Không","cn":"","loai":"bi-thuat","loaiLabel":"Phân thân kiếm ý","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Vân Không"],"blurb":"Kiếm ý phân thân của Vân Không là phân thân đượcngưng tụ từ kiếm ý của bổn tôn Vân Không, mang theo sáu thành kiếm ý và được phái tới truy kích Vương Lâm tại Đan Hải. Dù không phải bổn tôn, phân thân vẫn đủ sức thay mặt truy kích mục tiêu và duy trì uy lực để phá cấm chế.","detail":"Phân thân này không phải bổn tôn Vân Không mà là một thực thể tạo thành từ sáu thành kiếm ý của bổn tôn. Với lượng kiếm ý đó, phân thân đủ sức hóa thành hình dạng một thanh y tu sĩ, cầm trường kiếm bảy thước và tiếp tục truy kích Vương Lâm tại Đan Hải, đồng thời chém sụp tầng cấm chế thứ năm. Trong tiến trình, phân thân xuất hiện để thay bổn tôn duy trì cuộc truy kích Vương Lâm (@c1751).","thuocTinh":"kiếm ý phân thân","uyLuc":"Có sáu thành kiếm ý của bổn tôn Vân Không.","congNang":["Thay bổn tôn Vân Không truy kích mục tiêu (Vương Lâm) tại Đan Hải @c1751","Hóa thành hình dạng thanh y tu sĩ cầm trường kiếm bảy thước","Duy trì uy lực kiếm ý để phá cấm chế, chém sụp tầng cấm chế thứ năm"],"nguoiTu":[{"ten":"Vân Không","tuChuong":"@c1751","tangDatToi":"sáu thành kiếm ý của bổn tôn","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1751","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện thân truy kích","text":"Vân Không xuất hiện bằng kiếm ý phân thân có sáu thành kiếm ý của bổn tôn và tiếp tục truy kích Vương Lâm qua cấm chế Đan Hải.","anchor":"Cho dù là phân thân nhưng hắn lại có được sáu thành kiếm ý của bổn tôn!"}]},"capNhatToi":"@c1751","nguon":["@c1751"],"dacDiem":"Phân thân ngưng tụ từ kiếm ý, mang sáu thành kiếm ý của bổn tôn, hóa thành thanh y tu sĩ cầm trường kiếm bảy thước."},{"id":"thuy-hoa-chuong-an","name":"Thủy hỏa chưởng ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông bổn nguyên","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông do Vương Lâm phối hợp bổn tôn, hỏa bổn nguyên chân thân và thủy bổn nguyên từ đại hải tạo thành. Khi va chạm kiếm khí Vân Không, thủy hỏa dung hợp tạo sức bộc phát vượt từng bổn nguyên riêng lẻ.","detail":"Trong lúc bị Vân Không truy kích ở tầng bảy cấm chế Đan Hải, Vương Lâm xoay người phản kích bằng ba chưởng ấn: bổn tôn, hỏa bổn nguyên chân thân và thủy bổn nguyên từ đại hải. Sự dung hợp thủy hỏa không triệt tiêu nhau vì đều là bổn nguyên của Vương Lâm, mà bộc phát mạnh hơn để phá kiếm khí truy sát.","thuocTinh":"Thủy hỏa bổn nguyên","uyLuc":"Phá được kiếm khí truy kích của Vân Không trong Đan Hải.","dacDiem":"Dựa trên việc thủy và hỏa bổn nguyên cùng thuộc Vương Lâm nên có thể dung hợp trong giao kích.","congNang":["Thủy hỏa phối hợp phá kiếm khí truy kích trong cấm chế Đan Hải @c1752"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1752","tangDatToi":"thi triển trong giao chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1752","loai":"thi triển","importance":"normal","giaiDoan":"Phản kích Vân Không","text":"Vương Lâm dùng thủy hỏa chưởng ấn va chạm kiếm khí Vân Không, tạo bộc phát vượt từng bổn nguyên riêng lẻ.","anchor":"Thủy và hỏa trong nháy mắt này dung hợp."}]},"dinhDanh":"goc","capNhatToi":"@c1752","nguon":["@c1752"]},{"id":"khi-bon-nguyen","name":"Khí bổn nguyên","cn":"","loai":"khac","loaiLabel":"Bổn nguyên lực","phamCap":"bổn nguyên lực quý hiếm","hePhai":"Bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Khí bổn nguyên được hé lộ khi thủy hỏa bổn nguyên của Vương Lâm dung hợp trong lúc phá kiếm khí Vân Không. Đây là lực lượng khó có được, quý hơn bổn nguyên bình thường.","detail":"Khí bổn nguyên do thủy hỏa bổn nguyên ngưng tụ diễn biến mà thành, xuất hiện khi một người đồng thời nắm giữ cả hai lực lượng này. Trong lần giao phong ở Đan Hải, lực lượng này giúp Vương Lâm phá tan kiếm khí của Vân Không.","thuocTinh":"Khí","nguonGoc":"Do thủy hỏa bổn nguyên ngưng tụ diễn biến ra.","uyLuc":"Giúp phá tan kiếm khí của Vân Không trong lần giao phong ở Đan Hải.","dacDiem":"Không dễ đạt được, cần một người đồng thời nắm giữ thủy hỏa bổn nguyên.","congNang":["Diễn biến từ thủy hỏa bổn nguyên để bộc phát lực lượng vượt từng bổn nguyên riêng lẻ @c1752"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1752","tangDatToi":"lần đầu diễn biến trong giao chiến","trangThai":"đang nắm giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c1752","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Thủy hỏa sinh khí","text":"Khí bổn nguyên được hé lộ khi thủy hỏa bổn nguyên của Vương Lâm dung hợp trong lúc phá kiếm khí Vân Không.","anchor":"Nó không phải rõ ràng có thể có được mà phải là một người đồng thời nắm giữ thủy hỏa bổn nguyên"}]},"dinhDanh":"goc","capNhatToi":"@c1752","nguon":["@c1752"]},{"id":"kiem-khi-cua-van-khong","name":"Kiếm khí của Vân Không","cn":"","loai":"than-thong","loaiLabel":"Kiếm ý thần thông","phamCap":"chưa rõ","hePhai":"Lục Ma Châu","soHuu":["Vân Không"],"blurb":"Kiếm khí truy kích của Vân Không có thể đánh tan tầng sáu cấm chế Đan Hải và ngưng thành kiếm ảnh ngập trời. Trong chương này, nó lần đầu bị thủy hỏa chưởng ấn cùng khí bổn nguyên phá nát hoàn toàn.","detail":"Vân Không dùng kiếm khí đánh tan tầng sáu rồi nhanh chóng ngưng tụ thành kiếm ảnh ngập trời để chặn Vương Lâm ở tầng bảy. Khi Vương Lâm dùng thủy hỏa chưởng ấn phản kích, kiếm khí này lần đầu hoàn toàn tan nát, tạo cơ hội cho Vương Lâm thoát vào sương mù cấm chế.","thuocTinh":"Kiếm khí","uyLuc":"Đánh tan tầng sáu cấm chế Đan Hải và truy kích qua tầng bảy.","dacDiem":"Có thể ngưng tụ thành kiếm ảnh ngập trời sau khi phá tầng cấm chế.","congNang":["Đánh tan tầng sáu cấm chế Đan Hải và truy kích mục tiêu trong tầng bảy @c1752"],"nguoiTu":[{"ten":"Vân Không","tuChuong":"@c1752","tangDatToi":"thi triển truy kích","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1752","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát Vương Lâm","text":"Vân Không dùng kiếm khí đánh tan tầng sáu và truy kích Vương Lâm, nhưng bị thủy hỏa chưởng ấn cùng khí bổn nguyên phá nát.","anchor":"Kiếm khí kia sau khi đánh tan tầng sáu nhanh chóng ngưng tụ lại"}]},"dinhDanh":"goc","capNhatToi":"@c1752","nguon":["@c1752"]},{"id":"kiem-khi-huyet-sac-cua-van-khong","name":"Kiếm khí huyết sắc của Vân Không","cn":"","loai":"bi-thuat","loaiLabel":"Kiếm khí huyết thuật","phamCap":"chưa rõ","hePhai":"Lục Ma Châu","soHuu":["Vân Không"],"blurb":"Kiếm khí huyết sắc do Vân Không cắn lưỡi phun máu hóa thành khi Dĩ Ti khôi lỗi áp sát. Nó chém đứt tay phải khôi lỗi nhưng không ngăn được hắc khí Đạo Cổ nhập thể.","detail":"Khi Dĩ Ti khôi lỗi bất ngờ lao tới, Vân Không dùng máu tươi hóa thành kiếm khí huyết sắc để phản kích cận thân. Kiếm khí này chém rơi tay phải Dĩ Ti khôi lỗi, nhưng cánh tay bị chém lại hóa năm luồng hắc khí chui vào cơ thể Vân Không.","thuocTinh":"Huyết sắc kiếm khí","uyLuc":"Chém đứt tay phải Dĩ Ti khôi lỗi trong cận chiến.","dacDiem":"Do máu tươi của Vân Không hóa thành trong tình huống nguy cấp.","congNang":["Phản kích cận thân và chém đứt tay phải Dĩ Ti khôi lỗi @c1752"],"nguoiTu":[{"ten":"Vân Không","tuChuong":"@c1752","tangDatToi":"thi triển cận chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1752","loai":"thi triển","importance":"normal","giaiDoan":"Chém tay Dĩ Ti khôi lỗi","text":"Vân Không phun máu hóa kiếm khí huyết sắc, chém đứt tay phải Dĩ Ti khôi lỗi khi bị phục kích.","anchor":"Máu tươi phun ra lập tức hóa thành một kiếm khí huyết sắc"}]},"dinhDanh":"goc","capNhatToi":"@c1752","nguon":["@c1752"]},{"id":"khong-che-tam-than-bang-lan-khoi","name":"Khống chế tâm thần bằng làn khói","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông khống chế","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật nhập thân của Vương Lâm, hóa thành làn khói chui vào thân thể đối phương để cưỡng ép khống chế tâm thần.","detail":"Trong trận quanh cấm chế Đan Hải, Vương Lâm từ thân tu sĩ bị khống chế hóa thành làn khói chui vào hai mắt nam tử trung niên Không Niết sơ kỳ, dùng đối phương làm vỏ bọc áp sát nữ tử cầm la bàn.","thuocTinh":"Nhập thân, khống chế tâm thần","congNang":["Hóa thành làn khói rời khỏi thân xác đang khống chế và nhập vào mục tiêu mới để điều khiển hành động @c1754"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1754","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1754","loai":"thi triển","importance":"normal","giaiDoan":"Áp sát nữ tử cầm la bàn","text":"Vương Lâm dùng làn khói chuyển từ thân tu sĩ sang nam tử trung niên Không Niết sơ kỳ để tiếp tục khống chế tâm thần.","anchor":"Từ mi tâm của tu sĩ này chui ra một làn khói"}]},"nguon":["@c1754"]},{"id":"bon-nguyen-tan","name":"Bổn nguyên tán","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông kích phát bổn nguyên","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn Vương Lâm dùng khi mượn thân nam tử trung niên để phát động tập kích, khiến thân thể đối phương sụp đổ và phối hợp Vạn Tịnh Hóa Ô Dịch bùng nổ.","detail":"Trong khoảnh khắc bị la bàn phát hiện, Vương Lâm điều khiển nam tử trung niên phát ra tiếng gầm, khiến thân xác sụp đổ và bản thân hiện ra, đồng thời kích hoạt giọt chất lỏng đen thành hắc thủy bao phủ nghìn trượng.","thuocTinh":"Kích phát, hiện thân, phối hợp bổn nguyên chi dịch","congNang":["Dùng thân xác đang khống chế làm điểm phát động, chuyển sang hiện thân và kích hoạt tập kích diện rộng @c1754"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1754","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1754","loai":"thi triển","importance":"normal","giaiDoan":"Kích hoạt hắc thủy","text":"Vương Lâm mượn thân nam tử trung niên gầm nhẹ, khiến thân thể sụp đổ và mở đầu đợt tập kích bằng hắc thủy.","anchor":"nam tử trung niên do Vương Lâm khống chế đột nhiên phát ra một tiếng gầm nhẹ"}]},"nguon":["@c1754"]},{"id":"kiem-y-cua-van-khong","name":"Kiếm ý của Vân Không","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Kiếm đạo","phamCap":"Không rõ","hePhai":"Lục Ma Châu","soHuu":["Vân Không"],"blurb":"Kiếm ý và kiếm khí ngập trời của Vân Không bộc phát trong lúc hắn luyện hóa Đan Hải.","detail":"Khi Vân Không vận chuyển tu vi ở dòng xoáy thứ chín, cảnh giới cụ thể không được nói rõ, nhưng kiếm khí ngập trời và kiếm ý bao phủ tám phương, làm nổi bật khí thế của hắn trong quá trình ngưng tụ Đan Hải.","thuocTinh":"Kiếm khí, kiếm ý","uyLuc":"Kiếm khí ngập trời, bao phủ tám phương trong lúc luyện Đan Hải.","congNang":["Bộc phát kiếm khí và kiếm ý để trợ thế cho quá trình luyện hóa Đan Hải @c1754"],"nguoiTu":[{"ten":"Vân Không","tuChuong":"@c1754","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1754","loai":"thi triển","importance":"normal","giaiDoan":"Luyện Đan Hải","text":"Vân Không bộc phát kiếm khí và kiếm ý khi thúc đẩy Đan Hải co lại để ngưng tụ tiên đan.","anchor":"chỉ có thể cảm nhận được một cổ kiếm khí ngập trời"}]},"nguon":["@c1754"]},{"id":"ngung-tu-dan-hai","name":"Ngưng tụ Đan Hải","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Đại thuật luyện hóa","phamCap":"Không rõ","hePhai":"Lục Ma Châu","soHuu":["Vân Không"],"blurb":"Đại thuật Vân Không thi triển để luyện hóa nước biển Đan Hải, ngưng tụ nửa hạt tiên đan từ hải vực này.","detail":"Vân Không ngồi tại dòng xoáy thứ chín, bắt quyết khiến chín dòng xoáy và nước biển Đan Hải chuyển động dữ dội, thu nhỏ hải vực và sinh ra tiên khí, mục tiêu là ngưng tụ lại nửa hạt tiên đan để phá màn ngăn Thiên Ngưu Châu.","thuocTinh":"Luyện hóa, ngưng đan, điều động hải vực","congNang":["Luyện hóa cả Đan Hải, ép nước biển co lại và ngưng tụ nửa hạt tiên đan @c1754"],"nguoiTu":[{"ten":"Vân Không","tuChuong":"@c1754","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1754","loai":"thi triển","importance":"normal","giaiDoan":"Dòng xoáy thứ chín","text":"Vân Không bắt quyết làm nước biển Đan Hải chuyển động nhanh hơn, thu nhỏ hải vực để ngưng tụ tiên đan.","anchor":"Đan Hải, ngưng! Ầm một tiếng, nước biển bốn phía chuyển động nhanh hơn"}]},"nguon":["@c1754"]},{"id":"cam-che-che-dau-tren-la-ban","name":"Cấm chế che dấu trên la bàn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Cấm chế che dấu nằm trên la bàn cổ kính mà Vương Lâm thu được. Nó có tác dụng che giấu khu vực và được Vương Lâm đánh giá là có thể làm cấm chế bổn nguyên của hắn tăng lên nếu cắn nuốt dung hợp.","detail":"Vương Lâm khuếch tán và nghịch chuyển cấm chế này để che vùng chữa thương trong núi gần Đan Hải. Hắn nhận định cấm chế rất huyền diệu, nhưng chưa vội dung hợp vì trước mắt nó còn hữu dụng trong việc ẩn giấu.","thuocTinh":"che giấu","uyLuc":"Có thể che vùng chữa thương của Vương Lâm và khiến hắn đánh giá cao giá trị dung hợp với cấm chế bổn nguyên.","dacDiem":"Cấm chế có đặc tính che giấu, được gắn với la bàn cổ kính.","congNang":["Che giấu khu vực Vương Lâm chữa thương gần Đan Hải @c1756","Có thể được cắn nuốt dung hợp để tăng cấm chế bổn nguyên của Vương Lâm @c1756"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1756","tangDatToi":"khai thác bằng khuếch tán và nghịch chuyển","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1756","loai":"xuất hiện","importance":"normal","giaiDoan":"che giấu vùng chữa thương","text":"Vương Lâm dùng cấm chế che dấu trên la bàn để bảo hộ khu vực chữa thương, đồng thời nhận ra nó có thể tăng cấm chế bổn nguyên nếu dung hợp.","anchor":"Cấm chế che dấu này cũng thật huyền diệu, sau khi cắn nuốt dung hợp xong"}]},"dinhDanh":"goc","capNhatToi":"@c1756","nguon":["@c1756"]},{"id":"ho-mon-dai-tran-dai-hon-mon","name":"Hộ môn đại trận Đại Hồn Môn","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp","phamCap":"không rõ","hePhai":"Đại Hồn Môn","soHuu":["Đại Hồn Môn"],"blurb":"Đại trận bảo vệ sơn môn Đại Hồn Môn trong thời chiến. Trận pháp vừa tạo sát khí giới nghiêm vừa kiểm tra thân phận người trở về tông môn.","detail":"Khi Vương Lâm trở về, đại trận khiến thiên địa quanh sơn môn vặn vẹo và sát khí tràn ngập. Nó được dùng để quét thân thể người trở về, loại trừ thần thức và Nguyên Thần khác tồn tại trong cơ thể.","congNang":["Giới nghiêm và bảo vệ sơn môn Đại Hồn Môn trong thời chiến @c1757","Kiểm tra thân phận, quét thân thể, thanh trừ thần thức và Nguyên Thần lạ @c1757"],"tabs":{"tienTrinh":[{"chuong":"@c1757","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới nghiêm sơn môn","text":"Hộ môn đại trận được mở quanh sơn môn Đại Hồn Môn để kiểm tra Vương Lâm bằng lệnh bài, thần thức và máu tươi.","anchor":"Nó có tác dụng chủ yếu là thanh trừ thần thức và Nguyên Thần khác tồn tại trong cơ thể Vương Lâm"}]},"nguon":["@c1757"]},{"id":"phuong-phap-luyen-che-tu-hon","name":"Phương pháp luyện chế tử hồn","cn":"","loai":"bi-thuat","loaiLabel":"Bí pháp luyện hồn","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Đại Hồn Môn"],"blurb":"Bí pháp luyện người hoặc thú vào thời khắc trước khi chết để tạo tử hồn dùng cho Quỷ Phàm.","detail":"Đại Hồn Môn từng nghiên cứu tử hồn và tìm ra phương pháp luyện chế người hoặc thú trước khi tử vong. Phương pháp này có giới hạn, chỉ có thể tạo Quỷ Phàm sơ phẩm hoặc nhiều nhất là trung phẩm.","congNang":["Tạo tử hồn làm nền cho việc luyện chế Quỷ Phàm @c1758"],"dacDiem":"Chỉ đủ tạo tử hồn cấp thấp, khó đạt phẩm chất cao.","trangThai":"đã lộ phương pháp","nguoiTu":[],"tabs":{"tienTrinh":[{"chuong":"@c1758","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ phương pháp","text":"Đại Hồn Môn lộ từng tìm được cách luyện chế tử hồn từ người hoặc thú trước lúc chết, nhưng giới hạn ở Quỷ Phàm sơ phẩm hoặc trung phẩm.","anchor":"từ từ tìm được một phương pháp luyện chế người hoặc thú trước khi tử vong"}]},"capNhatToi":"@c1758","nguon":["@c1758"]},{"id":"tran-phap-cam-che-bay-thien-nguu-huyet","name":"Trận pháp cấm chế bảy Thiên Ngưu huyệt","cn":"","aliases":["Bảy Thiên Ngưu huyệt"],"loai":"khac","loaiLabel":"Trận pháp / cấm chế","phamCap":"","hePhai":"Đại Hồn Môn","soHuu":["Đại Hồn Môn"],"blurb":"Trận pháp cấm chế được hình thành từ bảy Thiên Ngưu huyệt do các đời tổ tiên Đại Hồn Môn mở theo bảy tinh huyệt của Thiên Ngưu Châu.","detail":"Bảy Thiên Ngưu huyệt có thể mượn lực lượng của Thiên Ngưu để hình thành một trận pháp cấm chế cực mạnh, đồng thời có nhiều huyền diệu đối với tu sĩ ở trong đó. Đây là một phần chuẩn bị lâu dài của Đại Hồn Môn trước việc Lục Ma Châu sẽ xâm phạm Thiên Ngưu Châu trên quy mô lớn.","nguon":["@c1759"]},{"id":"hoa-bon-nguyen-chan-than","name":"Hỏa bổn nguyên chân thân","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Chân thân bổn nguyên","phamCap":"Không rõ","hePhai":"Hỏa bổn nguyên","soHuu":["Vương Lâm"],"blurb":"Hỏa bổn nguyên chân thân của Vương Lâm có thể ngưng tụ từ biển lửa và dung hợp trở lại vào cơ thể.","detail":"Khi Vương Lâm rời ngọn núi, biển lửa bên ngoài lập tức ngưng tụ sau lưng hắn thành hỏa bổn nguyên chân thân rồi dung hợp vào thân thể, thể hiện khả năng thu phóng và nhập thể của chân thân.","congNang":["Ngưng tụ biển lửa thành chân thân rồi dung hợp vào thân thể @c1760"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1760","tangDatToi":"Có thể thu phóng nhập thể","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1760","loai":"thi triển","importance":"normal","giaiDoan":"Dung hợp nhập thể","text":"Hỏa bổn nguyên chân thân ngưng tụ từ biển lửa bên ngoài ngọn núi rồi dung hợp vào cơ thể Vương Lâm.","anchor":"biển lửa bên ngoài ngọn núi lập tức ngưng tụ lại phía sau hắn"}]},"capNhatToi":"@c1760","nguon":["@c1760"]},{"id":"truyen-tong-tran-toi-gan-thien-nguu-de-tam-huyet","name":"Truyền tống trận tới gần Thiên Ngưu đệ tam huyệt","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Đại Hồn Môn"],"blurb":"Truyền tống trận cổ do lão tổ đời đầu Đại Hồn Môn dùng đại thần thông tạo ra, có thể đưa người tới gần Thiên Ngưu đệ tam huyệt.","detail":"Trận pháp nằm trong một sơn cốc, được Lữ Văn Nhiễm dùng ngọc giản xác định và kích hoạt. Nó giúp bốn trưởng lão vượt quãng đường vốn phải phi hành mấy tháng để xuất hiện gần Cực Thiên thảo nguyên.","nguonGoc":"Lão tổ đời đầu Đại Hồn Môn dùng đại thần thông tạo thành","congNang":["Truyền tống xa tới gần Thiên Ngưu đệ tam huyệt @c1760"],"tabs":{"tienTrinh":[{"chuong":"@c1760","loai":"xuất hiện","importance":"normal","giaiDoan":"Kích hoạt truyền tống","text":"Lữ Văn Nhiễm dùng ngọc giản kích hoạt truyền tống trận cổ, đưa đội bốn trưởng lão tới gần Thiên Ngưu đệ tam huyệt.","anchor":"năm đó lão tổ đời đầu tiên của Đại Hồn Môn ta dùng đại thần thông tạo thành một truyền tống trận"}]},"capNhatToi":"@c1760","nguon":["@c1760"]},{"id":"cam-che-phong-ho-dia-cung-thien-nguu-de-tam-huyet","name":"Cấm chế phòng hộ Địa Cung Thiên Ngưu đệ tam huyệt","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm chế phòng hộ","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Đại Hồn Môn"],"blurb":"Cấm chế phòng hộ bao phủ nhiều lớp bên ngoài quần thể cung điện dưới Thiên Ngưu đệ tam huyệt.","detail":"Bên ngoài Địa Cung có tầng tầng lớp lớp cấm chế phòng hộ. Người không có thân phận trưởng lão Đại Hồn Môn và lệnh bài khó tiến vào khu vực này.","congNang":["Phòng hộ quần thể Địa Cung dưới Thiên Ngưu đệ tam huyệt @c1760"],"tabs":{"tienTrinh":[{"chuong":"@c1760","loai":"xuất hiện","importance":"normal","giaiDoan":"Phòng hộ Địa Cung","text":"Cấm chế phòng hộ nhiều lớp bao phủ bên ngoài quần thể cung điện dưới đất.","anchor":"Bên ngoài quần thể cung điện này có tầng tầng lớp lớp cấm chế phòng hộ"}]},"capNhatToi":"@c1760","nguon":["@c1760"]},{"id":"hon-dan","name":"Hồn Dẫn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông mà Vương Lâm đang tìm hiểu trong lúc tĩnh tọa tại động phủ ở Cực Thiên thảo nguyên.","detail":"Trong thời gian chờ đại chiến, Vương Lâm vừa luyện hóa chiếc ô màu lam vừa tìm hiểu Hồn Dẫn. Chương chưa hé lộ chiêu thức cụ thể của thần thông này.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1761","tangDatToi":"đang tìm hiểu","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1761","loai":"nhắc tới","importance":"bridge","giaiDoan":"Tìm hiểu trong động phủ","text":"Vương Lâm nhân lúc tĩnh tọa để tìm hiểu Hồn Dẫn.","anchor":"Nhân việc này hắn luyện hóa chiếc ô màu lam và tìm hiểu thần thông Hồn Dẫn"}]},"capNhatToi":"@c1761","nguon":["@c1761"]},{"id":"thien-nguu-that-huyet-dai-tran","name":"Thiên Ngưu thất huyệt đại trận","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"chưa rõ","hePhai":"Thiên Ngưu Châu","soHuu":[],"blurb":"Thiên Ngưu thất huyệt đại trận là đại trận phòng hộ dựa trên bảy Thiên Ngưu huyệt, lần đầu được triển khai hoàn toàn khi quân Lục Ma Châu đánh tới, tạo màn phòng hộ ngăn cách Thiên Ngưu Châu với Đan Hải.","detail":"Đại trận triển khai từ bảy Thiên Ngưu huyệt, hợp thành màn phòng hộ ngăn cách Thiên Ngưu Châu với Đan Hải. Nó mượn lực hơn mười vạn tu sĩ, kết hợp cấm chế trận pháp cùng lực lượng Thiên Ngưu Hồn để củng cố phòng tuyến, đồng thời có thể ngưng tụ sương mù Thiên Ngưu phản kích tu sĩ Lục Ma Châu. Trận này lần đầu được triển khai hoàn toàn khi quân Lục Ma Châu đánh tới (@c1761).","congNang":["Tạo màn phòng hộ ngăn cách Thiên Ngưu Châu với Đan Hải @c1761","Mượn lực hơn mười vạn tu sĩ, cấm chế và Thiên Ngưu Hồn để củng cố phòng tuyến","Ngưng tụ sương mù Thiên Ngưu phản kích tu sĩ Lục Ma Châu"],"uyLuc":"Khi triển khai hoàn toàn, đại trận khiến cả tu sĩ cấp Thanh Ngưu lão tổ cũng khó mở tấm màn phòng hộ từ bên ngoài.","trangThai":"đang triển khai","tabs":{"tienTrinh":[{"chuong":"@c1761","loai":"xuất hiện","importance":"major","giaiDoan":"Triển khai hoàn toàn","text":"Thiên Ngưu thất huyệt đại trận lần đầu được triển khai hoàn toàn, tạo màn phòng hộ và phản kích quân Lục Ma Châu bằng sương mù Thiên Ngưu.","anchor":"Thiên Ngưu thất huyệt này từ khi được tạo ra tới hiện tại, lần đầu tiên được triển khai hoàn toàn"}]},"capNhatToi":"@c1761","nguon":["@c1761"]},{"id":"cam-che-cuc-thien-thao-nguyen","name":"Cấm chế Cực Thiên thảo nguyên","cn":"","loai":"khac","loaiLabel":"Trận pháp cấm chế","phamCap":"chưa rõ","hePhai":"Thiên Ngưu Châu","soHuu":[],"blurb":"Cấm chế tại Cực Thiên thảo nguyên, được mở hoàn toàn khi người Đại Hồn Môn tới trấn thủ.","detail":"Cấm chế này tạo tường khí ngàn dặm và trở thành một phần của phòng tuyến Thiên Ngưu thất huyệt. Vương Lâm dùng la bàn cấm chế âm thầm dò xét nó mà Lữ Văn Nhiễm không phát hiện.","congNang":["Tạo tường khí ngàn dặm tại Cực Thiên thảo nguyên.","Kết nối vào phòng tuyến Thiên Ngưu thất huyệt."],"trangThai":"đã mở hoàn toàn","tabs":{"tienTrinh":[{"chuong":"@c1761","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở cấm chế","text":"Cấm chế Cực Thiên thảo nguyên được mở hoàn toàn và tạo tường khí phòng hộ.","anchor":"cấm chế trên Cực Thiên thảo nguyên đã hoàn toàn được mở ra"}]},"capNhatToi":"@c1761","nguon":["@c1761"]},{"id":"thien-nguu-hon","name":"Thiên Ngưu Hồn","cn":"","loai":"khac","loaiLabel":"Linh hồn trận pháp","phamCap":"chưa rõ","hePhai":"Thiên Ngưu Châu","soHuu":[],"blurb":"Lực lượng hồn phách gia trì cho Thiên Ngưu thất huyệt đại trận.","detail":"Thiên Ngưu Hồn là một phần sức mạnh của màn phòng hộ, khiến trận pháp khó bị phá từ bên ngoài. Khi quân Lục Ma Châu công kích, sương mù đen ngưng thành hình Thiên Ngưu rồi nổ tung phản kích.","congNang":["Gia trì màn phòng hộ Thiên Ngưu thất huyệt.","Ngưng tụ thành hình Thiên Ngưu trong sương mù để phản kích."],"tabs":{"tienTrinh":[{"chuong":"@c1761","loai":"thi triển","importance":"normal","giaiDoan":"Ngưng hình phản kích","text":"Thiên Ngưu Hồn ngưng tụ trong sương mù thành hình Thiên Ngưu và phản kích đợt công kích của Lục Ma Châu.","anchor":"còn có lực lượng của Thiên Ngưu Hồn"}]},"capNhatToi":"@c1761","nguon":["@c1761"]},{"id":"nguoi-khong-lo-van-truong-do-hai-lao-luc-ma-chau-bien-hoa","name":"Người khổng lồ vạn trượng do hai lão Lục Ma Châu biến hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"chưa rõ","hePhai":"Lục Ma Châu","soHuu":["Triệu huynh","Trương huynh"],"blurb":"Thần thông công kích do hai lão Không Kiếp trung kỳ phe Lục Ma Châu thi triển để thử Thiên Ngưu thất huyệt đại trận.","detail":"Hai lão bắt quyết, điểm một chỉ khiến vân khí hóa thành người khổng lồ cao vạn trượng trước mặt họ. Người khổng lồ này được dùng để đánh vào phòng tuyến Cực Thiên thảo nguyên.","uyLuc":"Được dùng trực tiếp để công kích đại trận phòng hộ.","tabs":{"tienTrinh":[{"chuong":"@c1761","loai":"thi triển","importance":"normal","giaiDoan":"Công kích đại trận","text":"Hai lão Không Kiếp trung kỳ Lục Ma Châu biến vân khí thành người khổng lồ vạn trượng để đánh vào đại trận.","anchor":"hóa thành một người khổng lồ cao vạn trượng trước mặt hai người"}]},"capNhatToi":"@c1761","nguon":["@c1761"]},{"id":"ba-thanh-phi-kiem-mau-den-do-than-thong-bien-hoa","name":"Ba thanh phi kiếm màu đen do thần thông biến hóa","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"chưa rõ","hePhai":"Lục Ma Châu","soHuu":["Triệu huynh","Trương huynh"],"blurb":"Ba thanh phi kiếm đen do thần thông của hai lão Không Kiếp trung kỳ Lục Ma Châu biến hóa ra.","detail":"Ba thanh phi kiếm màu đen lao ra từ vùng u quang trên trời, tỏa sát khí khiến cỏ xanh dưới đất héo rũ như bị hút sinh cơ. Chúng cùng người khổng lồ vạn trượng đánh vào phòng tuyến.","uyLuc":"Sát khí của phi kiếm khiến cỏ xanh héo rũ như bị hút đi sinh cơ.","tabs":{"tienTrinh":[{"chuong":"@c1761","loai":"thi triển","importance":"normal","giaiDoan":"Phi kiếm công trận","text":"Ba thanh phi kiếm đen lao ra từ u quang và cùng người khổng lồ công kích đại trận.","anchor":"Từ trong đó có ba thanh phi kiếm màu đen lao ra"}]},"capNhatToi":"@c1761","nguon":["@c1761"]},{"id":"tran-phap-cuc-thien-thao-nguyen-thien-nguu-de-tam-huyet","name":"Trận pháp Cực Thiên thảo nguyên Thiên Ngưu đệ tam huyệt","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thiên Ngưu Châu","soHuu":["Thiên Ngưu Châu"],"blurb":"Trận pháp sương mù tại Cực Thiên thảo nguyên Thiên Ngưu đệ tam huyệt, giúp phe phòng thủ thay đổi tương quan chiến lực.","detail":"Trận pháp tạo sương mù gây cản trở thần thức và hút tiên lực của tu sĩ Lục Ma Châu, khiến ba Không Kiếp sơ kỳ Thiên Ngưu Châu có thể miễn cưỡng kiềm chế một Không Kiếp trung kỳ.","congNang":["Tăng lợi thế phòng thủ trong sương mù cho phe Thiên Ngưu Châu @c1762"],"trangThai":"đang vận hành","capNhatToi":"@c1762","tabs":{"tienTrinh":[{"chuong":"@c1762","loai":"xuất hiện","importance":"normal","giaiDoan":"Đại chiến đệ tam huyệt","text":"Trận pháp phát huy tác dụng trong chiến trường sương mù, giúp phe Thiên Ngưu Châu kiềm chế lực lượng Không Kiếp mạnh hơn.","anchor":"Nhưng trận pháp tại Cực Thiên thảo nguyên Thiên Ngưu đệ tam huyệt này"}]},"nguon":["@c1762"]},{"id":"cong-phap-song-tu-hac-lien-cua-luu-chi-nguyen","name":"Công pháp song tu hắc liên của Lưu Chi Nguyên","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Lưu Chi Nguyên"],"blurb":"Công pháp song tu của Lưu Chi Nguyên, liên quan tới lô đỉnh và hắc liên. Chương này cho thấy công pháp có đại giá tàn khốc với các nữ tử lô đỉnh.","detail":"Công pháp ngưng tụ hồn phách lô đỉnh thành hắc liên, từng khiến vô số lô đỉnh chết trong tay Lưu Chi Nguyên. Hắc liên cũng hiện ra để cản Huyết Kiếm khi hắn bị Vương Lâm phục kích.","thuocTinh":"Song tu, hắc liên","nguonGoc":"Đạo Ma Tông","dacDiem":"Ngưng tụ hồn phách lô đỉnh và có thể hóa thành hắc liên hộ thân hoặc đối kháng công kích.","congNang":["Ngưng tụ hồn phách lô đỉnh thành hắc liên @c1762","Dùng hắc liên chống đỡ Huyết Kiếm khi bị đánh lén @c1762"],"nguoiTu":[{"ten":"Lưu Chi Nguyên","tuChuong":"@c1762","tangDatToi":"Không rõ","trangThai":"đang tu"}],"trangThai":"đang lưu truyền trong Đạo Ma Tông","capNhatToi":"@c1762","tabs":{"tienTrinh":[{"chuong":"@c1762","loai":"xuất hiện","importance":"normal","giaiDoan":"Lưu Chi Nguyên lộ công pháp","text":"Công pháp song tu hắc liên của Lưu Chi Nguyên lộ ra cùng các quả cầu lô đỉnh và hắc liên chống Huyết Kiếm.","anchor":"Công pháp hắn tu hành là công pháp song tu"}]},"nguon":["@c1762"]},{"id":"dan-hon-quy","name":"Dẫn Hồn Quy","cn":"","aliases":["Hồn Dẫn Quy"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông được Vương Lâm xem là thủ đoạn chém giết cuối cùng khi đối phó Không Kiếp sơ kỳ. Chương này nêu rõ nó có thể làm trọng thương Không Kiếp nhưng chưa bảo đảm giết chết hoàn toàn.","detail":"Trong kế hoạch phục kích Không Kiếp sơ kỳ, Vương Lâm đặt Dẫn Hồn Quy sau các thủ đoạn hỗ trợ như khôi lỗi Dĩ Ti, Huyết Kiếm, Dịch Linh Ấn và Đa Trọng Huyễn Thuật. Uy lực hiện được đánh giá là đủ khiến Không Kiếp trọng thương.","congNang":["Có thể khiến tu sĩ Không Kiếp sơ kỳ trọng thương @c1762"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1762","tangDatToi":"Không rõ","trangThai":"đang nắm giữ"}],"trangThai":"đang nắm giữ","capNhatToi":"@c1762","tabs":{"tienTrinh":[{"chuong":"@c1762","loai":"nhắc tới","importance":"normal","giaiDoan":"Sát chiêu cuối trong kế hoạch phục kích","text":"Vương Lâm xác định Dẫn Hồn Quy là thủ đoạn chém giết cuối cùng nhưng tự biết nó chỉ có thể làm Không Kiếp trọng thương.","anchor":"chính là Dẫn Hồn Quy"}]},"nguon":["@c1762"]},{"id":"bay-doa-hac-lien","name":"Bảy đóa hắc liên","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"chưa rõ","hePhai":"Lục Ma Châu","soHuu":["Lưu Chi Nguyên"],"blurb":"Thần thông của Lưu Chi Nguyên biến ra bảy đóa hắc liên trước người để chặn tập kích.","detail":"Lưu Chi Nguyên dùng bảy đóa hắc liên để phòng ngự trước khôi lỗi Dĩ Ti, nhưng bị đầu lưỡi của khôi lỗi xuyên phá trong trận phục kích.","thuocTinh":"hắc liên","congNang":["Phòng ngự chặn tập kích trực diện @c1763"],"nguoiTu":[{"ten":"Lưu Chi Nguyên","tuChuong":"@c1763","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1763","loai":"thi triển","importance":"normal","giaiDoan":"Chặn khôi lỗi Dĩ Ti","text":"Lưu Chi Nguyên biến ra bảy đóa hắc liên để ngăn khôi lỗi Dĩ Ti nhưng bị xuyên phá.","anchor":"tay áo vung lên. Lập tức trước người hắn liền có bảy đóa hắc liên biến ảo ra"}]},"capNhatToi":"@c1763","nguon":["@c1763"]},{"id":"chuong-an-hoa-diem","name":"Chưởng ấn hỏa diễm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông hỏa hệ","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Chưởng ấn do ngọn lửa tạo thành, xuất hiện sau lưng Lưu Chi Nguyên trong thế giáp kích.","detail":"Trong chuỗi vây sát, Vương Lâm khiến một chưởng ấn hỏa diễm xuất hiện sau lưng Lưu Chi Nguyên, phối hợp với chưởng ấn từ trên cao và các công kích khác.","thuocTinh":"hỏa diễm","congNang":["Giáp kích mục tiêu từ phía sau @c1763"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1763","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1763","loai":"thi triển","importance":"normal","giaiDoan":"Giáp kích Lưu Chi Nguyên","text":"Chưởng ấn hỏa diễm xuất hiện sau lưng Lưu Chi Nguyên trong chuỗi công kích của Vương Lâm.","anchor":"Một chưởng ấn do ngọn lửa tạo thành giống như thiêu đốt sương mù xuất hiện"}]},"capNhatToi":"@c1763","nguon":["@c1763"]},{"id":"huyet-giap-chan","name":"Huyết giáp chấn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông bảo mệnh","phamCap":"chưa rõ","hePhai":"Lưu Chi Nguyên","soHuu":["Lưu Chi Nguyên"],"blurb":"Thần thông bảo mệnh của Lưu Chi Nguyên, dùng máu hóa huyết giáp rồi nổ thành gió lốc phản chấn.","detail":"Lưu Chi Nguyên phun máu hóa thành huyết giáp phủ toàn thân, sau đó làm huyết giáp nổ tung thành cơn gió lốc để đánh tan chưởng ấn và ngạnh kháng nhiều công kích trong thế vây sát.","thuocTinh":"huyết","congNang":["Bảo mệnh và phản chấn nhiều công kích vây sát @c1763"],"nguoiTu":[{"ten":"Lưu Chi Nguyên","tuChuong":"@c1763","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1763","loai":"thi triển","importance":"normal","giaiDoan":"Phá thế vây sát","text":"Lưu Chi Nguyên dùng Huyết giáp chấn để phá chưởng ấn và chống đỡ khôi lỗi Dĩ Ti cùng Huyết Kiếm.","anchor":"huyết giáp phủ khắp toàn thân lập tức nổ tung, hình thành một cơn gió lốc quét ra"}]},"capNhatToi":"@c1763","nguon":["@c1763"]},{"id":"quyen-dao-co","name":"Quyền Đạo Cổ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông thể thuật Đạo Cổ","phamCap":"chưa rõ","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Một quyền thuộc Đạo Cổ của Vương Lâm, không hiện hư ảnh Đạo Cổ nhưng có uy lực đánh vỡ tay tu sĩ Không Kiếp sơ kỳ.","detail":"Vương Lâm xuất hiện sau lưng Lưu Chi Nguyên và tung Quyền Đạo Cổ, khiến cánh tay phải đối phương vỡ tung, mở màn truy kích cận chiến liên tục.","thuocTinh":"Đạo Cổ","uyLuc":"Đánh vỡ cánh tay phải của Lưu Chi Nguyên, một tu sĩ Không Kiếp sơ kỳ, trong cận chiến.","congNang":["Cận chiến phá thân thể mục tiêu mạnh @c1763"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1763","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1763","loai":"thi triển","importance":"normal","giaiDoan":"Đánh vỡ tay phải","text":"Vương Lâm dùng một quyền Đạo Cổ đánh vỡ cánh tay phải Lưu Chi Nguyên.","anchor":"Quyền này không có hư ảnh của Đạo Cổ nhưng lại là một quyền của Đạo Cổ"}]},"capNhatToi":"@c1763","nguon":["@c1763"]},{"id":"hon-dan-quy-thuat","name":"Hồn Dẫn Quy Thuật","cn":"","aliases":["Hồn huyễn trở về"],"loai":"than-thong","loaiLabel":"Thần thông triệu hồn","phamCap":"chưa rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông dùng máu huyết và đạo hồn để triệu dẫn anh hồn tổ tiên từ con đường máu.","detail":"Vương Lâm dùng máu huyết kích hoạt hồ lô hơn ba nghìn vạn đạo hồn, mở con đường máu và triệu hư ảnh La Vân Hải bước ra phá oan hồn của Lưu Chi Nguyên.","thuocTinh":"hồn, huyết dẫn","congNang":["Triệu dẫn anh hồn tổ tiên phá không mà tới @c1763"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1763","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1763","loai":"thi triển","importance":"normal","giaiDoan":"Triệu La Vân Hải","text":"Vương Lâm thi triển Hồn huyễn trở về để triệu hư ảnh La Vân Hải từ con đường máu.","anchor":"Lấy máu huyết của ta triệu dẫn anh hồn của tổ tiên từ cổ chí kim phá không mà tới"}]},"capNhatToi":"@c1763","nguon":["@c1763"]},{"id":"doan-khong-cam-tran","name":"Đoạn Không cấm trận","cn":"","aliases":[],"loai":"khac","loaiLabel":"Cấm trận","phamCap":"không rõ","hePhai":"Cấm Ma Tông","soHuu":["Cấm Ma Tông"],"blurb":"Cấm trận có khả năng ngăn thần thức dò xét, được nhận ra quanh nơi Vương Lâm giao chiến với Lưu Chi Nguyên. Dấu vết này khiến Lục Ma Châu liên hệ tới la bàn Đoạn Không cấm và nghi Vương Lâm.","detail":"Sau cái chết của Lưu Chi Nguyên, nữ tử Lục Ma Châu nhận ra lớp cấm chế che thần thức ngoài sương mù Thiên Ngưu trận pháp là Đoạn Không cấm trận của Cấm Ma Tông. Manh mối này nối với việc la bàn Đoạn Không cấm biến mất sau kịch biến Đan Hải, khiến phe Lục Ma Châu nghi Vương Lâm liên quan.","thuocTinh":"cấm chế che thần thức","nguonGoc":"Cấm Ma Tông","congNang":["Ngăn thần thức bên ngoài dò xét rõ diễn biến chiến đấu @c1764"],"dacDiem":"Có thể khiến thần thức của tu sĩ bên ngoài chỉ cảm nhận mơ hồ chiến trường bị che phủ.","trangThai":"được nhận ra qua dấu vết @c1764","capNhatToi":"@c1764","tabs":{"tienTrinh":[{"chuong":"@c1764","loai":"xuất hiện","importance":"normal","giaiDoan":"Bị nhận ra sau cái chết Lưu Chi Nguyên","text":"Nữ tử Lục Ma Châu nhận ra cấm chế che thần thức là Đoạn Không cấm trận của Cấm Ma Tông, từ đó mở ra manh mối truy xét Vương Lâm.","anchor":"Cấm chế này. Hẳn là Đoạn Không cấm trận của Cấm Ma Tông!"}]},"nguon":["@c1764"]},{"id":"doa-hoa-dau-lau","name":"Đóa hoa đầu lâu","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông tín hiệu","phamCap":"Không rõ","hePhai":"Lục Ma Châu","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông Hứa Đức Tài dùng để phóng tín hiệu trong lúc bị Vương Lâm tập kích. Hình thái là đóa hoa hư ảo khổng lồ, nhìn kỹ do đầu lâu hợp thành.","detail":"Hứa Đức Tài điểm chỉ lên trời khiến một đóa hoa hư ảo lớn hiện ra, che nửa bầu trời và báo vị trí Vương Lâm cho các nhóm truy binh đang áp sát.","thuocTinh":"Tín hiệu truy sát","uyLuc":"Dùng để triệu tập viện binh và bộc lộ vị trí giao chiến.","dacDiem":"Đóa hoa trông kiều diễm nhưng cấu thành từ đầu lâu.","congNang":["Báo hiệu vị trí mục tiêu cho lực lượng truy sát @c1767"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1767","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1767","loai":"thi triển","importance":"normal","giaiDoan":"Báo hiệu truy binh","text":"Hứa Đức Tài dùng Đóa hoa đầu lâu để báo vị trí Vương Lâm cho các đội Lục Ma Châu đang truy sát.","anchor":"một đóa hoa hư ảo kiều diễm bất ngờ hiện ra"}]},"capNhatToi":"@c1767","nguon":["@c1767"]},{"id":"su-anh-tram-van-an-ky","name":"Sư ảnh trăm vạn ấn ký","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"Không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông công kích do Hứa Đức Tài thi triển bằng tốc độ đánh ấn quyết cực nhanh. Hơn trăm vạn ấn ký hợp thành sư ảnh mấy trăm trượng lao vào Vương Lâm.","detail":"Hứa Đức Tài trong thời gian rất ngắn đánh ra hơn trăm vạn ấn ký, tạo thành sư ảnh khổng lồ gầm thét công kích Vương Lâm, làm nổi bật thủ đoạn thi pháp dị thường của hắn.","thuocTinh":"Ấn quyết công kích","uyLuc":"Tạo sư ảnh mấy trăm trượng lao vào đối thủ.","dacDiem":"Tốc độ kết ấn cực nhanh, vượt ngoài kinh nghiệm trước đó của Vương Lâm.","congNang":["Tạo sư ảnh khổng lồ để công kích trực diện @c1767"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1767","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1767","loai":"thi triển","importance":"normal","giaiDoan":"Công kích bằng sư ảnh","text":"Hứa Đức Tài đánh ra hơn trăm vạn ấn ký trong thời gian ngắn, ngưng tụ thành sư ảnh khổng lồ công kích Vương Lâm.","anchor":"bất ngờ trong thời gian ngắn ngủi đánh ra hơn trăm vạn ấn ký"}]},"capNhatToi":"@c1767","nguon":["@c1767"]},{"id":"bon-nguoi-dat-khong-lo","name":"Bốn người đất khổng lồ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông triệu hoán","phamCap":"Không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông triệu hoán công kích của Hứa Đức Tài. Hắn nhấn tay xuống đất, dùng lượng lớn ấn quyết gọi bốn người đất khổng lồ lao vào Vương Lâm.","detail":"Sau khi sư ảnh bị đối kháng, Hứa Đức Tài tiếp tục đánh ra gần bốn trăm vạn ấn quyết khiến bốn người đất khổng lồ từ dưới đất chui lên và áp sát Vương Lâm.","thuocTinh":"Triệu hoán đất","uyLuc":"Gọi bốn cự nhân đất cùng tham chiến.","dacDiem":"Liền mạch sau đòn sư ảnh, tạo áp lực nối tiếp bằng tốc độ ấn quyết cao.","congNang":["Triệu hoán bốn người đất khổng lồ để vây công đối thủ @c1767"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1767","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1767","loai":"thi triển","importance":"normal","giaiDoan":"Triệu hoán người đất","text":"Hứa Đức Tài dùng ấn quyết gọi bốn người đất khổng lồ từ mặt đất trồi lên công kích Vương Lâm.","anchor":"Chỉ thấy bốn người đất khổng lồ từ dưới đất chui lên"}]},"capNhatToi":"@c1767","nguon":["@c1767"]},{"id":"cay-huong-kinh-ngu","name":"Cây hương kình ngư","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông công kích tâm thần","phamCap":"Không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông Hứa Đức Tài dùng ở cuối trận trong chương 1767. Ấn quyết hóa thành cây hương, khi bái xuống làm tâm thần đối thủ chấn động và khói hương hóa thành mãnh thú giống kình ngư.","detail":"Hứa Đức Tài hóa gần năm trăm vạn ấn quyết thành một cây hương rồi vái Vương Lâm, khiến tâm thần Vương Lâm chấn động; sau đó khói hương biến thành mãnh thú giống kình ngư mở miệng cắn nuốt.","thuocTinh":"Tâm thần và thôn phệ","uyLuc":"Làm chấn động tâm thần đối thủ và hóa khói thành thú thôn phệ.","dacDiem":"Kết hợp nghi thức bái lạy với biến hóa khói hương thành kình ngư.","congNang":["Công kích tâm thần khi người thi triển vái bằng cây hương @c1767","Hóa khói hương thành mãnh thú giống kình ngư để cắn nuốt mục tiêu @c1767"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1767","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1767","loai":"thi triển","importance":"normal","giaiDoan":"Cây hương hóa kình ngư","text":"Hứa Đức Tài dùng cây hương do ấn quyết hóa thành để chấn động tâm thần Vương Lâm rồi biến khói hương thành mãnh thú giống kình ngư.","anchor":"hóa thành một cây hương, bị hắn nắm trong tay"}]},"capNhatToi":"@c1767","nguon":["@c1767"]},{"id":"ne-sat","name":"Nê sát","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông bùn đất do Hứa Đức Tài thi triển trong trận với Vương Lâm. Nó tạo màn bùn phong bế rồi co rút để vây khốn mục tiêu.","detail":"Hứa Đức Tài cắm hương, kết ấn cực nhanh rồi phát động Nê sát, khiến bùn đất dựng thành màn bao quanh Vương Lâm và đột nhiên co rút lại.","dinhDanh":"goc","thuocTinh":"bùn đất","uyLuc":"Có thể tạo màn phong bế và co rút ép đối thủ trong phạm vi khống chế.","dacDiem":"Được Hứa Đức Tài dùng như lớp mở đầu cho chuỗi công kích liên hoàn.","congNang":["Vây khốn và co rút ép đối thủ @c1768"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1768","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"thi triển","importance":"normal","giaiDoan":"Vây khốn Vương Lâm","text":"Hứa Đức Tài thi triển Nê sát, dùng bùn đất phong bế rồi co rút quanh Vương Lâm.","anchor":"Hứa Đức Tài gầm nhẹ, đám bùn này đột nhiên co rút lại"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"toc-do-thi-phap-di-thuong-cua-hua-duc-tai","name":"Tốc độ thi pháp dị thường của Hứa Đức Tài","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Khả năng thi pháp cực nhanh của Hứa Đức Tài, khiến hắn liên tục tung nhiều thủ đoạn trong thời gian rất ngắn. Vương Lâm nhận ra đây không phải tốc độ mà tu sĩ bình thường có thể có.","detail":"Trong trận chiến, Hứa Đức Tài gần như không để Vương Lâm có thời gian nghỉ hoặc triển khai thần thông đáp trả, vì các lớp công kích được hắn nối tiếp quá nhanh.","dinhDanh":"goc","thuocTinh":"thi pháp","uyLuc":"Giúp Hứa Đức Tài áp đảo nhịp giao chiến bằng số lượng thần thông liên hoàn.","dacDiem":"Vương Lâm cho rằng tốc độ này có thể đến từ cơ duyên hoặc một thần thông hiếm thấy.","congNang":["Tăng tốc độ kết ấn và thi triển nhiều loại thần thông liên tục @c1768"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1768","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"xuất hiện","importance":"normal","giaiDoan":"Áp chế nhịp giao chiến","text":"Khả năng thi pháp dị thường của Hứa Đức Tài lộ rõ khi hắn liên tục tung nhiều thủ đoạn khiến Vương Lâm khó kịp đáp trả.","anchor":"Điểm làm hắn khiến người ta có một cảm giác rất đáng sợ chính là tốc độ làm phép nhanh tới lạ thường"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"hu-anh-kinh-ngu-cua-hua-duc-tai","name":"Hư ảnh kình ngư của Hứa Đức Tài","cn":"","aliases":["Thiên Đạo của Hứa Đức Tài","Thiên Đạo kình ngư"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Hư ảnh kình ngư là Thiên Đạo hoặc thần thông cả đời của Hứa Đức Tài, có năng lực cắn nuốt đối thủ. Trong trận với Vương Lâm, nó bị U Minh Thú nuốt mất.","detail":"Hư ảnh kình ngư nhiều lần lao tới cắn nuốt, được mô tả là nếu nuốt tu sĩ cùng giai quá ba lần thì nhất định khiến người đó trọng thương. Khi nó tiếp tục tấn công Vương Lâm, U Minh Thú xuất hiện và hút nuốt ngược nó vào miệng, khiến Hứa Đức Tài thổ huyết và điên cuồng vì mất đi thứ được xem là Thiên Đạo của mình.","dinhDanh":"goc","thuocTinh":"cắn nuốt","trangThai":"bị U Minh Thú nuốt @c1768","uyLuc":"Có thể khiến tu sĩ cùng giai trọng thương nếu bị nuốt vào trên ba lần.","dacDiem":"Được Hứa Đức Tài xem là Thiên Đạo của mình, nên việc bị nuốt khiến hắn thổ huyết và điên cuồng.","congNang":["Cắn nuốt đối thủ và gây trọng thương cho tu sĩ cùng giai nếu lặp lại nhiều lần @c1768"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1768","tangDatToi":"không rõ","trangThai":"bị mất"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"thi triển","importance":"major","giaiDoan":"Bị U Minh Thú nuốt","text":"Hư ảnh kình ngư của Hứa Đức Tài tiếp tục cắn nuốt Vương Lâm nhưng bị U Minh Thú hút nuốt vào miệng.","anchor":"Một khi bị kình ngư này nuốt vào trên ba lần, tu sĩ cùng giai nhất định bị trọng thương"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"mang-xa-mau-den-phun-doc-khi","name":"Mãng xà màu đen phun độc khí","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông biến hóa ra chín mãng xà màu đen phun độc khí. Độc khí dung nhập vào khối bùn đang vây Vương Lâm trong chuỗi công kích của Hứa Đức Tài.","detail":"Sau khi màn bùn hình thành, bốn phía hiện ra chín con mãng xà màu đen, phun độc khí phối hợp với Nê sát để tăng áp lực lên Vương Lâm.","dinhDanh":"goc","thuocTinh":"độc khí","congNang":["Biến hóa mãng xà phun độc khí thấm nhập vào thế vây @c1768"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1768","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"thi triển","importance":"normal","giaiDoan":"Phối hợp Nê sát","text":"Hứa Đức Tài biến hóa chín mãng xà màu đen phun độc khí vào thế vây quanh Vương Lâm.","anchor":"bốn phía có chín con mãng xà màu đen biến ảo ra"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"phi-kiem-mau-vang","name":"Phi kiếm màu vàng","cn":"","aliases":[],"loai":"kiem-quyet","loaiLabel":"Kiếm quyết","phamCap":"không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Đám phi kiếm màu vàng được Hứa Đức Tài thi triển trong trận với Vương Lâm. Chúng bao vây và chém lên thân thể Vương Lâm, khiến hắn lùi lại và y phục tổn hại.","detail":"Phi kiếm vàng là một lớp công kích trong chuỗi thần thông liên hoàn của Hứa Đức Tài, đánh trực diện lên thân thể Đạo Cổ của Vương Lâm và tạo sức ép rõ rệt.","dinhDanh":"goc","thuocTinh":"kim kiếm","uyLuc":"Có thể chém ép thân thể Đạo Cổ khiến Vương Lâm phải lui lại.","congNang":["Bao vây và chém ép mục tiêu bằng nhiều phi kiếm màu vàng @c1768"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1768","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"thi triển","importance":"normal","giaiDoan":"Chém lên thân thể Vương Lâm","text":"Đám phi kiếm màu vàng lao tới chém lên người Vương Lâm, khiến hắn vội vàng lùi lại.","anchor":"Toàn bộ phi kiếm nọ rơi vào người hắn khiến thân thể Vương Lâm vội vàng lui lại phía sau"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"muoi-tam-nguoi-bun-tu-bao","name":"Mười tám người bùn tự bạo","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông tạo ra mười tám người bùn áp sát rồi tự bạo quanh Vương Lâm. Vụ nổ tạo cơn lốc hủy diệt khiến hắn phun máu.","detail":"Mười tám người bùn tiến vào phạm vi mười trượng quanh Vương Lâm rồi đồng loạt tự bạo, trở thành một lớp sát thương mạnh trong chuỗi công kích nối tiếp của Hứa Đức Tài.","dinhDanh":"goc","thuocTinh":"bùn đất tự bạo","uyLuc":"Tự bạo sinh ra cơn lốc hủy diệt đủ khiến Vương Lâm phun máu.","congNang":["Tạo người bùn áp sát rồi tự bạo gây hủy diệt phạm vi gần @c1768"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1768","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"thi triển","importance":"normal","giaiDoan":"Tự bạo quanh Vương Lâm","text":"Mười tám người bùn tiến tới gần Vương Lâm rồi tự bạo, tạo sát thương nối tiếp trong thế vây.","anchor":"mười tám người bùn này, một tấm màn đang nhúc nhích tiến tới"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"tam-man-hoa-muoi-van-tam-ngan-soi-to","name":"Tấm màn hóa mười vạn tám ngàn sợi tơ","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông biến tấm màn thành mười vạn tám ngàn sợi tơ xâm nhập cơ thể đối thủ. Nó được Hứa Đức Tài dùng để phá hoại Vương Lâm từ bên trong.","detail":"Sau lớp người bùn tự bạo, tấm màn tiếp tục biến hóa thành vô số sợi tơ chui vào cơ thể Vương Lâm, trở thành một đòn xâm nhập nội thể trong chuỗi công kích.","dinhDanh":"goc","thuocTinh":"xâm nhập cơ thể","congNang":["Hóa thành nhiều sợi tơ chui vào cơ thể đối thủ để phá hoại bên trong @c1768"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1768","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"thi triển","importance":"normal","giaiDoan":"Xâm nhập thân thể Vương Lâm","text":"Tấm màn của Hứa Đức Tài hóa thành mười vạn tám ngàn sợi tơ chui vào cơ thể Vương Lâm.","anchor":"hóa thành mười vạn tám ngàn sợi tơ"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"hai-ban-tay-khong-lo-tu-suong-mu-may-den","name":"Hai bàn tay khổng lồ từ sương mù mây đen","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Hứa Đức Tài","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông ngưng sương mù và mây đen thành hai bàn tay khổng lồ. Hai bàn tay đánh ép từ hai bên khiến Vương Lâm tuôn huyết vụ.","detail":"Trong chuỗi công kích dồn dập, sương mù cuốn mây đen hóa thành hai bàn tay khổng lồ đánh ép vào hai bên sườn Vương Lâm, gây thương thế rõ rệt cho thân thể hắn.","dinhDanh":"goc","thuocTinh":"sương mù mây đen","uyLuc":"Ép thương thân thể, khiến toàn thân Vương Lâm tuôn huyết vụ.","congNang":["Ngưng hai bàn tay khổng lồ đánh ép mục tiêu từ hai phía @c1768"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1768","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1768","loai":"thi triển","importance":"normal","giaiDoan":"Đánh ép Vương Lâm","text":"Sương mù và mây đen hóa thành hai bàn tay khổng lồ đánh ép vào Vương Lâm.","anchor":"hóa thành một đôi bàn tay khổng lồ"}]},"capNhatToi":"@c1768","nguon":["@c1768"]},{"id":"than-thong-truy-tung-bang-la-ban-hu-ao","name":"Thần thông truy tung bằng la bàn hư ảo","cn":"","loai":"than-thong","loaiLabel":"Thần thông truy tung","phamCap":"Không rõ","hePhai":"Lục Ma Châu","soHuu":["Nữ tu Không Kiếp bên cạnh Cực Thiên thảo nguyên"],"blurb":"Thủ đoạn phối hợp với la bàn hư ảo để xác định vị trí Vương Lâm và theo dõi các lần hắn biến mất, tái xuất.","detail":"Nữ tu Không Kiếp dùng thủ đoạn này để quan sát điểm sáng đại biểu cho Vương Lâm trên la bàn hư ảo, qua đó phát hiện hắn liên tục xuất hiện cạnh các nhóm tu sĩ Lục Ma Châu.","congNang":["Hiển thị vị trí mục tiêu qua la bàn hư ảo @c1769"],"tabs":{"tienTrinh":[{"chuong":"@c1769","loai":"thi triển","importance":"normal","giaiDoan":"Truy tung Vương Lâm","text":"Nữ tu Không Kiếp dùng la bàn hư ảo xác định rõ vị trí Vương Lâm và biến hóa của các điểm sáng trên Cực Thiên thảo nguyên.","anchor":"La bàn hư ảo phía trước nàng giờ phút này hiển thị rõ ràng vị trí của Vương Lâm"}]},"nguon":["@c1769"]},{"id":"kim-thien-thoat-xac-bang-nguyen-than-va-la-ban","name":"Kim thiền thoát xác bằng nguyên thần và la bàn","cn":"","loai":"bi-thuat","loaiLabel":"Mưu thuật","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Mưu kế dùng nguyên thần bị xóa ý chí điều khiển la bàn làm mồi nhử, khiến kẻ truy sát đuổi sai hướng.","detail":"Vương Lâm nhập thần trí vào một nguyên thần còn nguyên vẹn, để nguyên thần thiêu đốt điều khiển la bàn bay đi, qua đó tách nhóm Không Kiếp truy sát và đảo vai từ con mồi thành thợ săn.","congNang":["Đánh lạc hướng truy sát và chia cắt đội hình đối phương @c1769"],"tabs":{"tienTrinh":[{"chuong":"@c1769","loai":"thi triển","importance":"normal","giaiDoan":"Mồi nhử la bàn","text":"Vương Lâm dùng nguyên thần điều khiển la bàn bay đi làm mồi nhử, khiến nhóm truy sát tiếp tục bám theo la bàn giả.","anchor":"Dùng phương pháp này như kim thiền thoát xác, khiến cho Vương Lâm trong nháy mắt từ con mồi trở thành thợ săn!"}]},"nguon":["@c1769"]},{"id":"sat-tran-trong-khong-gian-thach","name":"Sát trận trong Không Gian Thạch","cn":"","loai":"khac","loaiLabel":"Trận pháp sát trận","phamCap":"Không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Sát trận trong Không Gian Thạch là chiến trường phục kích do Vương Lâm dựng nên bên trong không gian của Không Gian Thạch, kết hợp pháp bảo, khôi lỗi và nhiều bổn nguyên. Trận được hoàn tất để dẫn dụ và truy sát đối phương tiến vào.","detail":"Vương Lâm lần đầu đưa thân thể vào Không Gian Thạch, dùng ô màu lam, hồ lô đạo hồn, kim ấn, Quỷ Phàm, Văn Vương, khôi lỗi Dĩ Ti cùng các bổn nguyên để biến không gian bên trong thành chiến trường phục kích. Sau khi hoàn tất bố trí, hắn chuẩn bị dẫn người truy sát tiến vào để tiêu diệt.","congNang":["Bố trí chiến trường phục kích bên trong Không Gian Thạch @c1769"],"tabs":{"tienTrinh":[{"chuong":"@c1769","loai":"xuất hiện","importance":"major","giaiDoan":"Sát trận hoàn thành","text":"Vương Lâm hoàn tất bố trí sát trận trong Không Gian Thạch và chuẩn bị dẫn người truy sát tiến vào.","anchor":"Sát trận đã thành. Tiếp theo chính là dẫn người tiến vào sát trận!"}]},"nguon":["@c1769"]},{"id":"nhan-qua-bon-nguyen-kiem-than-thong","name":"Nhân quả bổn nguyên kiếm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông bổn nguyên","phamCap":"Không rõ","hePhai":"Bổn nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông do Vương Lâm dùng nhân quả bổn nguyên hóa thành kiếm. Trong trận với Hứa Đức Tài, kiếm này phá đám u hồn do đối phương tạo ra.","detail":"Vương Lâm vận nhân quả bổn nguyên tạo thành trường kiếm, đại biểu cho lực lượng nhân quả của hắn. Kiếm lao ra chém sụp thần thông u hồn phủ trời của Hứa Đức Tài, mở đầu việc cắt đứt tiết tấu thi pháp của đối thủ.","congNang":["Dùng lực lượng nhân quả hóa kiếm để phá thần thông u hồn @c1770"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1770","tangDatToi":"Hóa kiếm đối địch","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1770","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến Hứa Đức Tài","text":"Vương Lâm dùng nhân quả bổn nguyên hóa kiếm, chém sụp u hồn do Hứa Đức Tài tạo ra.","anchor":"Kiếm này đại biểu cho nhân quả bổn nguyên của Vương Lâm"}]},"capNhatToi":"@c1770","nguon":["@c1770"]},{"id":"sinh-tu-bon-nguyen-kiem-than-thong","name":"Sinh tử bổn nguyên kiếm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông bổn nguyên","phamCap":"Không rõ","hePhai":"Bổn nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông do Vương Lâm dùng sinh tử bổn nguyên hóa thành kiếm. Kiếm này đối kháng mãng xà do trường thương thần thông của Hứa Đức Tài biến ra.","detail":"Sinh tử bổn nguyên được Vương Lâm ngưng thành trường kiếm, gào thét lao tới trong không gian chỉ định. Nó chém vào mãng xà khổng lồ của Hứa Đức Tài, khiến hai bên cùng tan nát.","congNang":["Hóa kiếm đối kháng và phá thần thông mãng xà @c1770"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1770","tangDatToi":"Hóa kiếm đối địch","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1770","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến Hứa Đức Tài","text":"Vương Lâm dùng sinh tử bổn nguyên hóa kiếm, chém trúng mãng xà do trường thương thần thông của Hứa Đức Tài biến thành.","anchor":"trường kiếm do sinh tử bổn nguyên biến thành đã gào thét lao tới"}]},"capNhatToi":"@c1770","nguon":["@c1770"]},{"id":"chan-gia-bon-nguyen-kiem-than-thong","name":"Chân giả bổn nguyên kiếm","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông bổn nguyên","phamCap":"Không rõ","hePhai":"Bổn nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Thần thông do Vương Lâm dùng chân giả bổn nguyên hóa thành kiếm. Nó ép Hứa Đức Tài phải đánh ra thần thông thứ ba khi chưa hoàn thành.","detail":"Chân giả bổn nguyên kiếm xuất hiện cực nhanh trong lúc Hứa Đức Tài chưa kịp hoàn tất lần bắt quyết tiếp theo. Áp lực từ kiếm này buộc đối thủ đánh ra chiêu chưa hoàn chỉnh, làm đứt đoạn ưu thế tốc độ thi pháp của hắn.","congNang":["Ép đối thủ tung chiêu chưa hoàn thành và làm rối tiết tấu thi pháp @c1770"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1770","tangDatToi":"Hóa kiếm áp sát","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1770","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến Hứa Đức Tài","text":"Vương Lâm dùng chân giả bổn nguyên hóa kiếm áp sát, khiến Hứa Đức Tài không kịp hoàn thành thần thông thứ ba.","anchor":"Thanh kiếm do chân giả bổn nguyên của Vương Lâm biến thành đã xuất hiện"}]},"capNhatToi":"@c1770","nguon":["@c1770"]},{"id":"than-thong-suong-mu-do-u-hon-cua-hua-duc-tai","name":"Thần thông sương mù đỏ u hồn của Hứa Đức Tài","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lục Ma Châu","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông do Hứa Đức Tài dùng ấn ký hóa thành sương mù đỏ và u hồn. Trong trận với Vương Lâm, nó bị nhân quả bổn nguyên kiếm phá vỡ.","detail":"Hứa Đức Tài bắt quyết cực nhanh, tạo mấy trăm vạn ấn ký thành sương mù đỏ rồi hóa ra nhiều u hồn phủ trời ngập đất lao tới. Đây là chiêu đầu tiên của hắn trong không gian chỉ định nhưng bị Vương Lâm dùng nhân quả bổn nguyên kiếm chém sụp.","congNang":["Triệu u hồn phủ trời ngập đất để công kích mục tiêu @c1770"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1770","tangDatToi":"Thi triển trong giao chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1770","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến Vương Lâm","text":"Hứa Đức Tài dùng mấy trăm vạn ấn ký tạo sương mù đỏ và u hồn, nhưng bị nhân quả bổn nguyên kiếm phá vỡ.","anchor":"bất ngờ hóa thành mấy trăm, mấy ngàn tia u hồn phủ trời ngập đất lao tới"}]},"capNhatToi":"@c1770","nguon":["@c1770"]},{"id":"than-thong-truong-thuong-mang-xa-cua-hua-duc-tai","name":"Thần thông trường thương mãng xà của Hứa Đức Tài","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Lục Ma Châu","soHuu":["Hứa Đức Tài"],"blurb":"Thần thông của Hứa Đức Tài dùng ấn ký tạo trường thương rồi hóa thành mãng xà. Nó bị sinh tử bổn nguyên kiếm của Vương Lâm phá trong không gian chỉ định.","detail":"Hứa Đức Tài tiếp tục dùng tốc độ thi pháp cực nhanh đánh ra gần bảy trăm vạn ấn ký, hình thành trường thương rồi biến thành mãng xà khổng lồ lao tới. Vương Lâm dùng sinh tử bổn nguyên kiếm đối phá, khiến hai bên cùng tan nát.","congNang":["Tạo trường thương biến thành mãng xà khổng lồ công kích @c1770"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1770","tangDatToi":"Thi triển trong giao chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1770","loai":"thi triển","importance":"normal","giaiDoan":"Đối chiến Vương Lâm","text":"Hứa Đức Tài tạo trường thương hóa mãng xà khổng lồ, rồi bị sinh tử bổn nguyên kiếm của Vương Lâm phá chiêu.","anchor":"Trường thương vừa hiện ra, lập tức liền vặn vẹo"}]},"capNhatToi":"@c1770","nguon":["@c1770"]},{"id":"thuy-bon-nguyen-bang-mau-huyet","name":"Thủy bổn nguyên bằng máu huyết","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông bổn nguyên","phamCap":"Không rõ","hePhai":"Bổn nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Cách Vương Lâm dùng máu huyết bản thân để ngưng tụ thủy bổn nguyên khi không gian không có nước. Nó được dung hợp với lôi hải và hỏa diệm sơn thành lực lượng hủy diệt.","detail":"Trong không gian chỉ định của Không Gian Thạch vốn không có nước, Vương Lâm phun máu để ngưng tụ thủy bổn nguyên. Thủy bổn nguyên này cùng lôi và hỏa bổn nguyên tạo thành thế dung hợp hủy diệt nhằm giết Hứa Đức Tài.","congNang":["Lấy máu huyết bản thân ngưng tụ thủy bổn nguyên trong không gian không có nước @c1770","Dung hợp với lôi hải và hỏa diệm sơn để tạo lực lượng hủy diệt @c1770"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1770","tangDatToi":"Ngưng tụ bằng máu huyết","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1770","loai":"thi triển","importance":"normal","giaiDoan":"Sát trận lôi hỏa thủy","text":"Vương Lâm dùng máu huyết bản thân ngưng tụ thủy bổn nguyên để dung hợp với lôi và hỏa trong sát cục.","anchor":"Vương Lâm lấy máu huyết bản thân, ngưng tụ ra thủy bổn nguyên"}]},"capNhatToi":"@c1770","nguon":["@c1770"]},{"id":"sau-dao-bon-nguyen","name":"Sáu đạo bổn nguyên","cn":"","loai":"than-thong","loaiLabel":"Bổn nguyên công kích","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Đợt công kích hợp lực từ sáu đạo bổn nguyên sinh tử, nhân quả, chân giả, hỏa, thủy và lôi của Vương Lâm.","detail":"Sáu đạo bổn nguyên ngưng tụ thành đợt chém giết đầu tiên trong sát trận, đủ khiến Hứa Đức Tài trọng thương nhưng chưa thể giết chết do đối phương có đèn lồng hộ thân.","congNang":["Hợp sáu đạo bổn nguyên để phát động công kích trực diện, đánh trọng thương tu sĩ Không Kiếp sơ kỳ @c1771"],"uyLuc":"Có thể trọng thương Hứa Đức Tài trong lần va chạm đầu tiên.","tabs":{"tienTrinh":[{"chuong":"@c1771","loai":"thi triển","importance":"normal","giaiDoan":"Đợt chém giết đầu tiên","text":"Vương Lâm hợp sáu đạo bổn nguyên để đánh Hứa Đức Tài trọng thương, nhưng đèn lồng hộ thân khiến đối phương chưa chết.","anchor":"Sáu đạo bổn nguyên ngưng tụ lại, triển khai một hồi chém giết ầm vang"}]},"capNhatToi":"@c1771","nguon":["@c1771"]},{"id":"quy-pham-thuat","name":"Quỷ Phàm","cn":"","loai":"than-thong","loaiLabel":"Thuật pháp Đại Hồn Môn","phamCap":"Không rõ","hePhai":"Đại Hồn Môn","soHuu":["Vương Lâm"],"blurb":"Thuật pháp Đại Hồn Môn dùng mây đen và quỷ hồn để nhiễu loạn tâm thần đối thủ.","detail":"Trong trận với Hứa Đức Tài, mây đen do Quỷ Phàm biến thành ngưng tụ thành bóng lưng nữ tử áo trắng, tiếng khóc thảm khiến tâm thần đối phương mê loạn.","congNang":["Nhiễu loạn tâm thần đối thủ bằng mây đen, quỷ hồn và hình ảnh nữ tử áo trắng @c1771"],"tabs":{"tienTrinh":[{"chuong":"@c1771","loai":"thi triển","importance":"normal","giaiDoan":"Nhiễu loạn Hứa Đức Tài","text":"Quỷ Phàm hóa mây đen và bóng lưng nữ tử áo trắng, khiến Hứa Đức Tài rơi vào mê loạn ngay sau khi thoát định thân.","anchor":"mây đen trên bầu trời ầm vang"}]},"capNhatToi":"@c1771","nguon":["@c1771"]},{"id":"ba-ngan-van-dao-hon","name":"Ba ngàn vạn đạo hồn","cn":"","loai":"than-thong","loaiLabel":"Hồn lực công kích","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lực lượng đạo hồn quy mô lớn được Vương Lâm gọi lên từ mặt đất để cuốn và oanh sát đối thủ.","detail":"Ba ngàn vạn đạo hồn bay lên như hắc khí, cuốn tuyết đen và thân thể Hứa Đức Tài lên bầu trời màu lam để phát động công kích hủy diệt.","congNang":["Cuốn đối thủ lên không, phối hợp cấm chế tuyết đen để phát nổ công kích @c1771"],"uyLuc":"Có thể cuốn Hứa Đức Tài khỏi mặt đất và tham gia đợt công kích tổng lực.","tabs":{"tienTrinh":[{"chuong":"@c1771","loai":"thi triển","importance":"normal","giaiDoan":"Cuốn Hứa Đức Tài lên không","text":"Ba ngàn vạn đạo hồn theo tay áo Vương Lâm bay lên, cuốn Hứa Đức Tài cùng tuyết đen lên bầu trời màu lam để oanh sát.","anchor":"ba ngàn vạn đạo hồn này liền cuốn theo tuyết đen"}]},"capNhatToi":"@c1771","nguon":["@c1771"]},{"id":"toc-than-quyet","name":"Tốc Thần Quyết","cn":"","loai":"than-thong","loaiLabel":"Thần thông/công pháp","phamCap":"không rõ","hePhai":"không rõ; có cảm giác gần thần thông Cổ Tộc","soHuu":["Hứa Đức Tài","Vương Lâm"],"blurb":"Tốc Thần Quyết là thuật tăng tốc độ thi triển thần thông, lộ ra khi Vương Lâm soát hồn Hứa Đức Tài. Cơ chế chính là mở chín thần mạch trong cơ thể người tu luyện để gia tăng tốc độ thi pháp. (+) Pháp quyết tốc độ của Vương Lâm, ở mốc sáu đạo thần mạch có thể tạo chín mươi bảy tàn ảnh phối hợp bản thể thi triển thần thông. [CAN-SOAT-GOP]","detail":"Tốc Thần Quyết bắt nguồn từ một đoạn ấn quyết mà Hứa Đức Tài từng gặp kỳ ngộ trên thiên thạch thiên ngoại. Thuật này lấy trọng tâm là chín thần mạch trong người tu luyện, mỗi thần mạch được mở ra sẽ giúp tăng tốc độ thi triển thần thông. Hứa Đức Tài đã mở được bảy thần mạch. Thuật được Vương Lâm phát hiện khi soát hồn Hứa Đức Tài; Vương Lâm nhận ra nếu dùng lực lượng thân thể Cổ Tộc để thi triển thì uy lực sẽ còn đáng sợ hơn nữa (@c1772).","thuocTinh":"tăng tốc thi triển thần thông","nguonGoc":"Đoạn ấn quyết trên thiên thạch thiên ngoại","yeuCau":"mở thần mạch trong cơ thể","uyLuc":"Có thể khiến tốc độ thi triển thần thông tăng rất mạnh; nếu dùng thân thể Cổ Tộc thi triển thì uy lực càng kinh khủng.","dacDiem":"Trọng tâm là chín thần mạch trong người tu luyện; mỗi thần mạch được mở giúp tăng tốc độ thi pháp.","congNang":["Tăng tốc độ thi triển thần thông qua việc mở chín thần mạch trong cơ thể @c1772"],"nguoiTu":[{"ten":"Hứa Đức Tài","tuChuong":"@c1772","tangDatToi":"bảy thần mạch","trangThai":"đã chết"},{"ten":"Vương Lâm","tuChuong":"@c1772","tangDatToi":"mới lấy được pháp quyết","trangThai":"đang nghiên cứu"}],"tabs":{"tienTrinh":[{"chuong":"@c1772","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ cơ chế chín thần mạch","text":"Vương Lâm soát hồn Hứa Đức Tài và phát hiện Tốc Thần Quyết, biết thuật này mở chín thần mạch để tăng tốc thi triển thần thông.","anchor":"Chủ yếu là nó mở ra trong người chín thần mạch"}]},"trangThai":"đã lộ cho Vương Lâm","capNhatToi":"@c1772","nguon":["@c1772","@c1825"]},{"id":"hai-hu-anh-khong-lo-cua-tu-si-luc-ma-chau","name":"Hai hư ảnh khổng lồ của tu sĩ Lục Ma Châu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Tu sĩ Lục Ma Châu Không Huyền trung kỳ truy sát lão già tóc bạc"],"blurb":"Thần thông tạo hai hư ảnh khổng lồ dùng để truy sát đối thủ trên chiến trường. Khi gặp Vương Lâm, hai hư ảnh này bị phá tan dễ dàng.","detail":"Tu sĩ Không Huyền trung kỳ Lục Ma Châu dùng hai hư ảnh khổng lồ để áp sát và công kích lão già tóc bạc Thiên Ngưu Châu. Vương Lâm xuất hiện, vung tay phá tan thần thông này, khiến người thi triển kinh hãi bỏ chạy.","congNang":["Tạo hai hư ảnh khổng lồ truy kích và công kích mục tiêu @c1773"],"uyLuc":"Có thể ép lão già tóc bạc Thiên Ngưu Châu tới đường cùng, nhưng không chịu nổi một lần phá giải của Vương Lâm.","dacDiem":"Biểu hiện thành hai hư ảnh khổng lồ gầm thét lao đi.","nguoiTu":[{"ten":"Tu sĩ Lục Ma Châu Không Huyền trung kỳ truy sát lão già tóc bạc","tuChuong":"@c1773","tangDatToi":"không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1773","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát lão già tóc bạc","text":"Tu sĩ Lục Ma Châu dùng hai hư ảnh khổng lồ truy sát lão già tóc bạc, nhưng bị Vương Lâm vung tay phá tan.","anchor":"Hai hư ảnh khổng lồ kia gầm thét hóa thành hai đạo cầu vồng lao thẳng về phía trước"}]},"capNhatToi":"@c1773","nguon":["@c1773"]},{"id":"truat","name":"Truất","cn":"","loai":"than-thong","loaiLabel":"Phong cấm thần thông","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Trương Đạo Tông"],"blurb":"Thần thông phong bế thiên địa do Trương Đạo Tông thi triển trong lúc truy sát Vương Lâm. Nó khiến Vương Lâm không thể dung nhập thiên địa để thoát thân.","detail":"Trương Đạo Tông phát ra một tiếng “Truất”, khiến thiên địa quanh Vương Lâm như bị phong ấn. Trong tình thế đó, Vương Lâm không thể dung hợp thiên địa, buộc phải gọi Văn Thú bỏ chạy bằng tốc độ phi hành.","congNang":["Phong bế thiên địa, ngăn mục tiêu dung nhập thiên địa để thoát thân @c1773"],"uyLuc":"Đủ khiến Vương Lâm mất phương án dung nhập thiên địa khi bị cao thủ Không Kiếp trung kỳ truy sát.","dacDiem":"Kích phát bằng một tiếng quát, hiệu quả thể hiện như thiên địa bị phong kín.","nguoiTu":[{"ten":"Trương Đạo Tông","tuChuong":"@c1773","tangDatToi":"không rõ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1773","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát Vương Lâm","text":"Trương Đạo Tông dùng tiếng “Truất” phong bế thiên địa, buộc Vương Lâm phải gọi Văn Thú bỏ chạy.","anchor":"Thiên địa lúc này giống như bị phong ấn, không cách nào dung hợp được!"}]},"capNhatToi":"@c1773","nguon":["@c1773"]},{"id":"tran-phap-dia-cung","name":"Trận pháp Địa Cung","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thiên Ngưu Châu","soHuu":["Thiên Ngưu Châu","Lữ Văn Nhiễm"],"blurb":"Trận pháp Địa Cung là phòng tuyến phong bế cuối cùng của phe Thiên Ngưu Châu dưới lòng đất. Khi Lục Ma sứ giả xuất hiện, Lữ Văn Nhiễm dùng nó để đóng kín Địa Cung.","detail":"Trong cuộc rút lui ở Cực Thiên thảo nguyên, Lữ Văn Nhiễm ra lệnh tu sĩ Thiên Ngưu Châu trở về Địa Cung và phong kín nơi đó. Trận pháp này nhanh chóng phong bế đại địa, khiến Vương Lâm phải liều mạng vượt vào trước khoảnh khắc đóng kín.","congNang":["Phong kín Địa Cung và ngăn cách tuyến phòng thủ dưới lòng đất với chiến trường bên ngoài @c1774"],"trangThai":"đã phong bế Địa Cung","capNhatToi":"@c1774","tabs":{"tienTrinh":[{"chuong":"@c1774","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong bế Địa Cung","text":"Trận pháp Địa Cung được kích hoạt để phong kín nơi trú thủ của Thiên Ngưu Châu trong lúc Lục Ma sứ giả truy sát.","anchor":"Cả vùng đất truyền đến hàng loạt dao động nhanh chóng phong bế"}]},"nguon":["@c1774"]},{"id":"tran-phap-phong-be-thien-nguu-de-tam-huyet","name":"Trận pháp phong bế Thiên Ngưu đệ tam huyệt","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thiên Ngưu Châu","soHuu":["Thiên Ngưu đệ tam huyệt"],"blurb":"Trận pháp phong bế khu vực quanh Thiên Ngưu đệ tam huyệt ngay sau khi Vương Lâm chui xuống lòng đất. Nó chặn đường giữa mặt đất và Địa Cung nhưng vẫn có nguy cơ bị sáu Không Kiếp trung kỳ công phá nếu bị đánh liên tục.","detail":"Khi Vương Lâm vừa tiến vào đại địa, khu vực này lập tức bị phong bế. Trận pháp đủ để tạm thời ngăn cản truy kích từ mặt đất, nhưng dưới công kích toàn lực kéo dài của sáu lão quái Không Kiếp trung kỳ Lục Ma Châu, nó sớm muộn cũng có thể bị đánh tung.","dinhDanh":"goc","congNang":["Phong bế khu vực Thiên Ngưu đệ tam huyệt và cắt đường truy kích giữa mặt đất với Địa Cung @c1775"],"tabs":{"tienTrinh":[{"chuong":"@c1775","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong bế sau khi Vương Lâm thoát xuống đất","text":"Trận pháp phong bế khu vực ngay sau khi Vương Lâm tiến vào đại địa, giúp hắn tránh bị sáu lão quái Không Kiếp trung kỳ chặn lại trên mặt đất.","anchor":"trong nháy mắt khi bản thân tiến vào đại địa, khu vực này đã bị phong bế"}]},"nguon":["@c1775"]},{"id":"hon-khai","name":"Hồn Khải","cn":"","aliases":["Thiên Ngưu Hồn Khải"],"loai":"than-thong","loaiLabel":"Thần thông / nghi thức triệu hồn","phamCap":"Không rõ","hePhai":"Thiên Ngưu đệ tam huyệt","soHuu":["Thiên Ngưu đệ tam huyệt","Thiên Ngưu Châu","Vương Lâm"],"blurb":"Thủ đoạn cuối cùng của Thiên Ngưu đệ tam huyệt, dùng toàn bộ tu vi của mọi người để gọi hồn phách Thiên Ngưu hóa thành áo giáp. Người mặc Hồn Khải có thể được Thiên Ngưu nhập thân và tăng tu vi cực mạnh trong thời gian ngắn.","detail":"Hồn Khải được lão già họ Chu công bố khi Địa Cung lâm nguy. Nghi thức cần mọi người dùng toàn bộ tu vi gọi hồn phách Thiên Ngưu, hóa thành áo giáp; người mặc có thể tiến công kẻ xông vào hoặc bảo vệ người phe mình rời đi.","dinhDanh":"goc","nguonGoc":"Thiên Ngưu đệ tam huyệt","yeuCau":"Cần mọi người dùng toàn bộ tu vi để gọi hồn phách Thiên Ngưu","uyLuc":"Có thể khiến người mặc được Thiên Ngưu nhập thân và tu vi tăng tới mức cực kỳ khủng bố trong thời gian ngắn","dacDiem":"Là thủ đoạn cuối cùng được giữ lại khi cứ điểm nguy cấp","congNang":["Gọi hồn phách Thiên Ngưu hóa thành áo giáp để nhập thân người mặc @c1775","Giúp người mặc trong thời gian ngắn tăng tu vi cực mạnh, có thể tiến công hoặc bảo vệ rút lui @c1775","Trợ giúp Vương Lâm thi triển Tàn Dạ và hiểu căn nguyên tín niệm của thần thông này @c1783"],"nguoiTu":[{"ten":"Lữ Văn Nhiễm","tuChuong":"@c1775","tangDatToi":"Được chọn làm người mặc","trangThai":"chuẩn bị"}],"tabs":{"tienTrinh":[{"chuong":"@c1775","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ thủ đoạn cuối cùng","text":"Hồn Khải được công bố là thủ đoạn cuối cùng của Thiên Ngưu đệ tam huyệt, cần mọi người dùng toàn bộ tu vi gọi hồn phách Thiên Ngưu hóa thành áo giáp cho người được chọn mặc.","anchor":"cần mọi người dùng toàn bộ tu vi, gọi về hồn phách Thiên Ngưu, hóa thành Hồn Khải"},{"chuong":"@c1783","loai":"thi triển","importance":"normal","giaiDoan":"Trợ lực Tàn Dạ","text":"Hồn Khải trợ giúp Vương Lâm thi triển Tàn Dạ, khiến hắn mơ hồ hiểu ra căn nguyên của thần thông này.","anchor":"Nhưng lúc này có sự trợ giúp của Hồn Khải, với tu vi hiện nay, thi triển ra Tàn Dạ khiến hắn mơ hồ hiểu ra."}]},"capNhatToi":"@c1775","nguon":["@c1775","@c1783"],"trangThai":"đang do Vương Lâm sử dụng"},{"id":"nghi-thuc-goi-thien-nguu-hon","name":"Nghi thức gọi Thiên Ngưu Hồn","cn":"","loai":"khac","loaiLabel":"Nghi thức trận pháp","phamCap":"Không rõ","hePhai":"Thiên Ngưu Châu","soHuu":["Lão già họ Chu","Lữ Văn Nhiễm"],"blurb":"Nghi thức huyết sắc dùng để mở dòng xoáy thông tới không gian phong ấn Thiên Ngưu và kéo Thiên Ngưu Hồn ra ngoài.","detail":"Lão già họ Chu lấy máu lập ấn quyết, mượn tu vi hơn ngàn tu sĩ mở dòng xoáy, rồi dùng chín tia máu mỗi người ngưng thành dây chuyền huyết sắc để khóa kéo Thiên Ngưu Hồn.","thuocTinh":"huyết sắc, triệu hồn, trận pháp","uyLuc":"Có thể dẫn động hồn phách Thiên Ngưu bị phong ấn và tạo điều kiện cho Hồn Khải hiện thế.","dacDiem":"Cần hơn ngàn tu sĩ cùng hiến tu vi và máu, lại cần Nguyên Thần tu sĩ Không Kiếp hợp lực khi dây chuyền không kéo tiếp được.","congNang":["Mở dòng xoáy tới không gian phong ấn Thiên Ngưu @c1776","Dùng dây chuyền huyết sắc khóa kéo Thiên Ngưu Hồn @c1776"],"nguoiTu":[{"ten":"Lão già họ Chu","tuChuong":"@c1776","tangDatToi":"chủ trì nghi thức","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1776","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở nghi thức Hồn Khải","text":"Lão già họ Chu dùng máu lập ấn, hấp thu tu vi hơn ngàn tu sĩ và tạo dây chuyền huyết sắc kéo Thiên Ngưu Hồn.","anchor":"Ấn ký huyết sắc kia là bước đầu tiên để gọi Thiên Ngưu Hồn"}]},"capNhatToi":"@c1776","nguon":["@c1776"]},{"id":"tat-dau-thanh-binh-son-bang-dia-liet","name":"Tát Đậu Thành Binh Sơn Băng Địa Liệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Cụm thần thông được Vương Lâm thi triển nối tiếp trong đợt bộc phát tốc độ cao chống Lữ Văn Nhiễm.","detail":"Khi dùng thần mạch tăng tốc vận chuyển tu vi, Vương Lâm gọi Tát Đậu Thành Binh Sơn Băng Địa Liệt như một phần của chuỗi thần thông liên hoàn, nối sau Hô Phong Hoán Vũ để tạo thế ép trong thời gian cực ngắn.","congNang":["Tạo thêm lớp công kích trong chuỗi thần thông liên hoàn @c1779"],"nguon":["@c1779"]},{"id":"phan-than-huyet-sac-cua-lu-van-nhiem","name":"Phân thân huyết sắc của Lữ Văn Nhiễm","cn":"","loai":"bi-thuat","loaiLabel":"Huyết thuật/phân thân","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Lữ Văn Nhiễm"],"blurb":"Huyết thuật do Lữ Văn Nhiễm thi triển bằng cách phun máu tươi hóa thành hai phân thân giống hệt mình.","detail":"Trong lúc Viêm Loan và Hứa Đông Đức sắp tới cản, Lữ Văn Nhiễm dùng máu tươi hóa ra hai phân thân huyết sắc để giữ chân họ trong vài nhịp thở, đổi lấy thời cơ tiếp tục truy sát Vương Lâm.","congNang":["Hóa máu tươi thành hai phân thân giống hệt bản thể để cầm chân đối thủ trong thời gian ngắn @c1779"],"nguoiTu":[{"ten":"Lữ Văn Nhiễm","tuChuong":"@c1779","tangDatToi":"thi triển được","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1779","loai":"thi triển","importance":"normal","giaiDoan":"Cầm chân cứu viện","text":"Lữ Văn Nhiễm phun máu hóa hai phân thân huyết sắc để chặn Viêm Loan và Hứa Đông Đức trong vài nhịp thở.","anchor":"Đám máu tươi này nhúc nhích hóa thành hai phân thân huyết sắc giống hệt hắn"}]},"nguon":["@c1779"]},{"id":"quy-pham-da-trong-huyen-thuat","name":"Quỷ Phàm Đa Trọng Huyễn Thuật","cn":"","loai":"than-thong","loaiLabel":"Huyễn thuật","phamCap":"không rõ","hePhai":"Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Huyễn thuật do Vương Lâm âm thầm thi triển lên Lữ Văn Nhiễm trước khi đối phương phát giác. Thuật này dẫn phát hình ảnh nữ tử bạch y khóc thảm trong tâm thần, góp phần khiến Lữ Văn Nhiễm phát cuồng.","detail":"Trong trận tại Địa Cung, Vương Lâm đã lặng lẽ thi triển Quỷ Phàm Đa Trọng Huyễn Thuật lên Lữ Văn Nhiễm. Khi Lữ Văn Nhiễm ghen ghét và công kích điên cuồng, trong tâm thần hắn hiện ra thân ảnh nữ tử bạch y khóc thảm, cho thấy thuật này có tác dụng tác động tâm thần và dẫn phát huyễn tượng.","thuocTinh":"huyễn thuật","uyLuc":"Tác động tâm thần tu sĩ Không Kiếp trung kỳ trong lúc giao chiến.","dacDiem":"Được thi triển âm thầm trước khi mục tiêu phát hiện.","congNang":["Tác động tâm thần và dẫn phát huyễn tượng trong lòng mục tiêu @c1780"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1780","tangDatToi":"không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1780","loai":"thi triển","importance":"normal","giaiDoan":"Âm thầm tác động Lữ Văn Nhiễm","text":"Vương Lâm lặng lẽ dùng Quỷ Phàm Đa Trọng Huyễn Thuật, khiến tâm thần Lữ Văn Nhiễm hiện nữ tử bạch y khóc thảm.","anchor":"Quỷ Phàm Đa Trọng Huyễn Thuật là vào lúc hắn không để Lữ Văn Nhiễm phát hiện ra mà yên lặng thi triển"}]},"dinhDanh":"goc","capNhatToi":"@c1780","nguon":["@c1780"]},{"id":"than-thong-hoa-thien-nguu-cua-hon-khai","name":"Thần thông hóa Thiên Ngưu của Hồn Khải","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"không rõ","hePhai":"Thiên Ngưu Hồn Khải","soHuu":["Vương Lâm"],"blurb":"Thần thông phát sinh khi Vương Lâm mặc Thiên Ngưu Hồn Khải. Tay và chân hắn có thể biến hóa thành hình thái Thiên Ngưu để công kích Lữ Văn Nhiễm.","detail":"Sau khi Thiên Ngưu Hồn Khải phủ lên thân, Vương Lâm vận dụng sức mạnh hóa thân liên quan tới Thiên Ngưu. Tay phải và chân phải hắn lần lượt biến hóa theo hình thái Thiên Ngưu, trong đó chân phải hóa thành sừng Thiên Ngưu để phá hủy thân thể Lữ Văn Nhiễm.","thuocTinh":"biến hóa thân thể, công kích","uyLuc":"Đánh nát thân thể tu sĩ Không Kiếp trung kỳ Lữ Văn Nhiễm.","dacDiem":"Gắn trực tiếp với trạng thái mặc Thiên Ngưu Hồn Khải.","congNang":["Biến bộ phận thân thể thành hình thái Thiên Ngưu để công sát mục tiêu @c1780"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1780","tangDatToi":"thi triển trong trạng thái Hồn Khải","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1780","loai":"thi triển","importance":"normal","giaiDoan":"Công sát Lữ Văn Nhiễm","text":"Vương Lâm mặc Hồn Khải, biến chân phải thành sừng Thiên Ngưu để phá hủy thân thể Lữ Văn Nhiễm.","anchor":"chân phải Vương Lâm bất ngờ biến ảo thành sừng của Thiên Ngưu"}]},"dinhDanh":"goc","capNhatToi":"@c1780","nguon":["@c1780"]},{"id":"luc-ma-hat-hon-tran-ap","name":"Lục Ma Hạt Hồn trấn áp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Trận thế/ý chí truyền thừa","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Lục Ma sứ giả"],"blurb":"Trận thế do bốn Lục Ma sứ giả thi triển, dùng bọ cạp lục khí và mặt gương hiện Lục Ma Châu để trấn áp khí tức Thiên Ngưu Hồn.","detail":"Bốn Lục Ma sứ giả tản ra, phun máu và gọi ra bốn bọ cạp màu lục, đồng thời ngưng mặt gương màu lục hiện Lục Ma Châu. Thế trấn áp này bao phủ Cực Thiên thảo nguyên nhằm đè xuống khí tức từ người được Thiên Ngưu Hồn tán thành.","dinhDanh":"goc","thuocTinh":"lục khí, ý chí Lục Ma Hạt Hồn","congNang":["Trấn áp khí tức Thiên Ngưu Hồn trên Cực Thiên thảo nguyên @c1781"],"nguoiTu":[{"ten":"Lục Ma sứ giả","tuChuong":"@c1781","tangDatToi":"gọi bốn bọ cạp lục khí và mặt gương Lục Ma Châu","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1781","loai":"thi triển","importance":"normal","giaiDoan":"Trấn áp Cực Thiên thảo nguyên","text":"Bốn Lục Ma sứ giả dùng bọ cạp lục khí và mặt gương Lục Ma Châu để hình thành thế trấn áp trên Cực Thiên thảo nguyên.","anchor":"bao trùm Cực Thiên thảo nguyên, hình thành thế trấn áp"}]},"capNhatToi":"@c1781","nguon":["@c1781"]},{"id":"ma-dao-dai-thu-an","name":"Ma Đạo đại thủ ấn","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông tối cao của Đạo Ma Tông","hePhai":"Đạo Ma Tông","soHuu":["Đạo Ma Tông","Trương Đạo Tông","Vương Lâm"],"blurb":"Ma Đạo đại thủ ấn là thần thông tối cao bí mật của Đạo Ma Tông, được Trương Đạo Tông nhận ra qua chưởng ấn sáu ngón do Vương Lâm thi triển. Thuật này vốn là bí mật bất truyền, chỉ tông chủ các đời mới nắm giữ.","detail":"Ma Đạo đại thủ ấn có nguồn gốc từ Đạo Ma Tông, được xác nhận là bí thuật tối cao bất truyền của tông môn này. Khi Vương Lâm thi triển chưởng ấn sáu ngón, Trương Đạo Tông kinh hãi nhận ra đó chính là Ma Đạo đại thủ ấn đã mở lục chỉ @c1782. Chương chỉ dừng ở việc xác nhận thân phận của thuật này mà chưa giải thích vì sao Vương Lâm có thể thi triển được.","thuocTinh":"Ma đạo","nguonGoc":"Đạo Ma Tông","dacDiem":"Hình thái trong chương là đại thủ ấn đã mở lục chỉ.","congNang":["Tạo đại thủ ấn lục chỉ có uy thế khiến Trương Đạo Tông nhận ra đây là bí thuật tối cao của Đạo Ma Tông @c1782"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1782","tangDatToi":"Lục chỉ","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1782","loai":"xuất hiện","importance":"major","giaiDoan":"Lục chỉ","text":"Trương Đạo Tông nhận ra chưởng ấn sáu ngón của Vương Lâm là Ma Đạo đại thủ ấn, bí mật bất truyền của Đạo Ma Tông.","anchor":"Đây là ma đạo đại thủ ấn! Hơn nữa còn là đại thủ ấn đã mở được lục chỉ"}]},"capNhatToi":"@c1782","nguon":["@c1782"]},{"id":"hinh-chieu-luc-ma-chau-tran-ap","name":"Hình chiếu Lục Ma Châu trấn áp","cn":"","aliases":[],"loai":"khac","loaiLabel":"Thuật trấn áp","phamCap":"Không rõ","hePhai":"Lục Ma Châu","soHuu":["Bốn Lục Ma sứ giả"],"blurb":"Thuật trấn áp do bốn Lục Ma sứ giả kích hoạt thông qua Lục Ma kính. Nó dùng hình chiếu cả Lục Ma Châu phủ lên Cực Thiên thảo nguyên để ép Vương Lâm.","detail":"Bốn Lục Ma sứ giả khiến gương màu lục chìm xuống và mở rộng bao phủ Cực Thiên thảo nguyên, biến cảnh thảo nguyên thành thiên địa ao đầm của Lục Ma Châu. Hình chiếu đại lục này được dùng để trấn áp Vương Lâm dưới lòng đất.","thuocTinh":"Trấn áp, hình chiếu đại lục","congNang":["Lấy hình chiếu cả Lục Ma Châu phủ lên chiến trường để trấn áp mục tiêu @c1782"],"nguoiTu":[{"ten":"Bốn Lục Ma sứ giả","tuChuong":"@c1782","tangDatToi":"Kích hoạt qua Lục Ma kính","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1782","loai":"xuất hiện","importance":"normal","giaiDoan":"Phủ Cực Thiên thảo nguyên","text":"Bốn Lục Ma sứ giả dùng gương màu lục tạo hình chiếu Lục Ma Châu phủ lên Cực Thiên thảo nguyên để trấn áp Vương Lâm.","anchor":"Lấy hình chiếu này tiến hành trấn áp"}]},"capNhatToi":"@c1782","nguon":["@c1782"]},{"id":"tin-thuat","name":"Tín thuật","cn":"","loai":"than-thong","loaiLabel":"Cấp độ thần thông","phamCap":"Vượt đạo thuật","hePhai":"Đại Thiên Tôn","soHuu":["Chín Đại Thiên Tôn","Vương Lâm"],"blurb":"Tín thuật là cấp độ thần thông vượt trên pháp thuật và đạo thuật thông thường, sinh ra từ tín niệm cá nhân đạt tới cực hạn. Tính tới mốc mới nhất, đây được nêu là cấp độ chỉ những tồn tại như Đại Thiên Tôn mới có thể nắm giữ.","detail":"Tín thuật bắt nguồn từ tín niệm cá nhân đạt cực hạn, không truyền thừa theo lối thường mà do chính niềm tin của người thi triển sinh ra. Được giải thích là thần thông vượt qua đạo thuật và vạn vật, nó có khả năng từ không biến thành có dựa trên tín niệm bản thân. Đây được nói là cấp độ chỉ những tồn tại như Đại Thiên Tôn mới có thể nắm giữ.","thuocTinh":"Tín niệm","nguonGoc":"Tín niệm cá nhân đạt cực hạn","uyLuc":"Vượt qua đạo thuật, uy lực khó hình dung.","dacDiem":"Không truyền thừa theo lối thường mà do niềm tin của người thi triển sinh ra.","trangThai":"đã hé lộ qua Tàn Dạ","capNhatToi":"@c1783","congNang":["Từ không biến thành có dựa trên tín niệm cá nhân @c1783","Vượt qua pháp thuật và đạo thuật thông thường @c1783"],"tabs":{"tienTrinh":[{"chuong":"@c1783","loai":"xuất hiện","importance":"major","giaiDoan":"Khái niệm được hé lộ","text":"Tín thuật được nêu là cấp độ thần thông vượt đạo thuật, vốn chỉ những tồn tại như Đại Thiên Tôn mới có thể nắm giữ.","anchor":"Tín thuật còn hơn cả đạo thuật, uy lực không cách nào hình dung nổi."}]},"nguon":["@c1783"]},{"id":"he-thong-phap-thuat-dao-thuat-tin-thuat","name":"Hệ thống Pháp thuật - Đạo thuật - Tín thuật","cn":"","loai":"khac","loaiLabel":"Phân tầng thần thông","phamCap":"Khung nhận thức tu luyện","hePhai":"Tiên Cương","soHuu":[],"blurb":"Hệ thống này phân biệt pháp thuật, đạo thuật và tín thuật theo ba nền tảng Ý Cảnh, bản nguyên và tín niệm. Đây là khung nhận thức được nêu khi Tàn Dạ lộ bản chất tín thuật.","detail":"Pháp thuật ứng với Ý Cảnh, đạo thuật ứng với bản nguyên, còn tín thuật ứng với tín niệm. Cách giải thích này nối quá trình tu luyện từ Ý Cảnh tới cảm ngộ bản nguyên, bản nguyên chân thân, chân thần rồi tới tín niệm làm nền tảng thần thông cao hơn.","thuocTinh":"Ý Cảnh, bản nguyên, tín niệm","dacDiem":"Pháp thuật ứng Ý Cảnh, đạo thuật ứng bản nguyên, tín thuật ứng tín niệm.","trangThai":"đã được giải thích","capNhatToi":"@c1783","congNang":["Làm khung phân tầng để nhận biết thần thông thông thường, đạo thuật và tín thuật @c1783"],"tabs":{"tienTrinh":[{"chuong":"@c1783","loai":"xuất hiện","importance":"normal","giaiDoan":"Giải thích phân tầng","text":"Chương nêu rõ pháp thuật, đạo thuật và tín thuật lần lượt ứng với Ý Cảnh, bản nguyên và tín niệm.","anchor":"Pháp thuật ứng với Ý Cảnh, đạo thuật ứng với bản nguyên, còn lại chính là tín niệm!"}]},"nguon":["@c1783"]},{"id":"thuan-di-buoc-qua-song-gon-khong-gian","name":"Thuấn di / bước qua sóng gợn không gian","cn":"","loai":"than-thong","loaiLabel":"Thần thông di chuyển","phamCap":"không rõ","hePhai":"không rõ","soHuu":["Vương Lâm"],"blurb":"Thủ đoạn di chuyển giúp Vương Lâm bước qua sóng gợn không gian và lập tức biến mất khỏi vị trí cũ. Trong chương này, hắn dùng nó để truy sát và chặn đường các Lục Ma sứ giả.","detail":"Khi Vương Lâm bước đi, sóng gợn lan ra dưới chân rồi thân ảnh biến mất trong nháy mắt. Thần thông này được dùng liên tục trong cuộc truy sát bốn Lục Ma sứ giả trên Cực Thiên thảo nguyên.","congNang":["Di chuyển tức thời để truy sát và chặn mục tiêu bỏ chạy @c1784"],"nguon":["@c1784"]},{"id":"luoi-set-phong-an","name":"Lưới sét phong ấn","cn":"","loai":"than-thong","loaiLabel":"Thần thông bản nguyên / phong ấn","phamCap":"không rõ","hePhai":"Lôi bản nguyên, Cấm chế bản nguyên","soHuu":["Vương Lâm"],"blurb":"Thần thông do Vương Lâm dung hợp lôi bản nguyên và cấm chế bản nguyên để tạo thành lưới sét phong ấn. Nó từng trói và ấn Lục Ma sứ giả hóa cơn lốc xuống đất.","detail":"Vương Lâm dùng lôi bản nguyên và cấm chế bản nguyên dung hợp thành tấm lưới sét, bao phủ Lục Ma sứ giả hóa cơn lốc. Lưới này kéo mục tiêu xuống đất và tạm phong ấn tu sĩ Không Kiếp trung kỳ.","thuocTinh":"Lôi, cấm chế","uyLuc":"Có thể phong ấn Lục Ma sứ giả Không Kiếp trung kỳ trong thời gian Vương Lâm được Hồn Khải gia trì.","congNang":["Tạo lưới sét cuốn mục tiêu, ấn xuống đất và phong ấn @c1784"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1784","tangDatToi":"thi triển trong thực chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1784","loai":"thi triển","importance":"normal","giaiDoan":"Phong ấn Lục Ma sứ giả hóa cơn lốc","text":"Vương Lâm dung hợp lôi bản nguyên và cấm chế bản nguyên thành lưới sét, cuốn lấy đối phương và phong ấn xuống mặt đất.","anchor":"lồi bản nguyên và cấm chế bản nguyên dung hợp thành phong ấn tấm lưới sét"}]},"nguon":["@c1784"]},{"id":"cau-tam-dao-ban-nguyen","name":"Cầu tám đạo bản nguyên","cn":"","loai":"than-thong","loaiLabel":"Thần thông bản nguyên","phamCap":"không rõ","hePhai":"Bản nguyên của Vương Lâm","soHuu":["Vương Lâm"],"blurb":"Đòn công kích do Vương Lâm ngưng tụ tám đạo bản nguyên thành quả cầu nhỏ. Thần thông này được dùng để phá Lục Ma nhập thể của Lục Ma sứ giả cưỡi hạc giấy.","detail":"Trong trạng thái được Thiên Ngưu Hồn Khải nâng lên Không Kiếp sơ kỳ, Vương Lâm mạnh mẽ dẫn tám đạo bản nguyên trong thân thể hóa thành tám sợi dây rồi ngưng thành cầu nhỏ. Cầu bản nguyên va chạm với Lục Ma nhập thể và tạo điều kiện cho Huyết Kiếm kết liễu đối thủ.","thuocTinh":"Tám đạo bản nguyên","uyLuc":"Phá được Lục Ma nhập thể của Lục Ma sứ giả Không Kiếp trung kỳ.","congNang":["Dung hợp tám bản nguyên thành cầu nhỏ để công kích trực diện @c1784"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1784","tangDatToi":"thi triển trong thực chiến","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1784","loai":"thi triển","importance":"normal","giaiDoan":"Phá Lục Ma nhập thể","text":"Vương Lâm ngưng tụ tám đạo bản nguyên thành quả cầu nhỏ để công kích Lục Ma sứ giả cưỡi hạc giấy.","anchor":"tám đạo bản nguyên trong thân thể bất ngờ hóa thành tám sợi dây"}]},"nguon":["@c1784"]},{"id":"luc-ma-nhap-the","name":"Lục Ma nhập thể","cn":"","loai":"than-thong","loaiLabel":"Thần thông Lục Ma Châu","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Lục Ma sứ giả cưỡi hạc giấy màu lục"],"blurb":"Thần thông của Lục Ma Châu được Lục Ma sứ giả cưỡi hạc giấy thi triển khi bị Vương Lâm chặn đường. Nó khiến thân thể phát ra lục quang ngập trời để chống lại đòn công kích bản nguyên.","detail":"Trong lúc sợ hãi, Lục Ma sứ giả cưỡi hạc giấy gầm lên thi triển Lục Ma nhập thể. Thần thông này va chạm với cầu tám đạo bản nguyên của Vương Lâm nhưng không chống đỡ được kết cục bị Huyết Kiếm chém chết.","thuocTinh":"Lục khí","congNang":["Gia trì thân thể bằng lục quang để đối kháng công kích @c1784"],"nguoiTu":[{"ten":"Lục Ma sứ giả cưỡi hạc giấy màu lục","tuChuong":"@c1784","tangDatToi":"thi triển trong thực chiến","trangThai":"đã chết"}],"tabs":{"tienTrinh":[{"chuong":"@c1784","loai":"thi triển","importance":"normal","giaiDoan":"Chống cầu bản nguyên","text":"Lục Ma sứ giả cưỡi hạc giấy dùng Lục Ma nhập thể khi đối diện cầu tám đạo bản nguyên của Vương Lâm.","anchor":"Lục Ma nhập thể! Giọng nói chói tai vang lên"}]},"nguon":["@c1784"]},{"id":"huyet-don-thuat-cua-luc-ma-su-gia","name":"Huyết độn thuật của Lục Ma sứ giả","cn":"","loai":"bi-thuat","loaiLabel":"Độn thuật","phamCap":"không rõ","hePhai":"Lục Ma Châu","soHuu":["Lục Ma sứ giả dùng huyết độn"],"blurb":"Độn thuật dùng máu để tăng tốc bỏ chạy. Một Lục Ma sứ giả đã liên tục phun máu khi chạy về phương bắc nhằm thoát khỏi Vương Lâm.","detail":"Lục Ma sứ giả dùng huyết độn không ngừng phun máu tươi trong lúc đào tẩu, khiến tốc độ tăng mạnh và thân ảnh hóa thành tàn ảnh. Dù vậy hắn vẫn bị Vương Lâm dùng Định thân giữ lại.","thuocTinh":"Huyết độn","congNang":["Tăng tốc đào tẩu bằng cách phun máu tươi @c1784"],"nguoiTu":[{"ten":"Lục Ma sứ giả dùng huyết độn","tuChuong":"@c1784","tangDatToi":"thi triển trong thực chiến","trangThai":"đã chết"}],"tabs":{"tienTrinh":[{"chuong":"@c1784","loai":"thi triển","importance":"normal","giaiDoan":"Đào tẩu phương bắc","text":"Lục Ma sứ giả dùng huyết độn phun máu liên tục để bỏ chạy về phương bắc.","anchor":"Trong lúc bỏ chạy, hắn không ngừng phun máu tươi"}]},"nguon":["@c1784"]},{"id":"truyen-tong-tran-toi-quy-nhat-tong","name":"Truyền Tống Trận tới Quy Nhất Tông","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Chưa rõ","hePhai":"Thiên Ngưu Châu","soHuu":["Quy Nhất Tông"],"blurb":"Trận pháp dùng để đưa các Thiên Ngưu sứ giả tới Quy Nhất Tông trong thời chiến. Âu Dương Chân giao ngọc giản cho Vương Lâm để sử dụng trận này ba lần.","detail":"Truyền Tống Trận này gắn với kế hoạch triệu tập sứ giả về Quy Nhất Tông. Ngọc giản của Âu Dương Chân ghi vị trí cụ thể và đủ để sử dụng trận ba lần.","congNang":["Truyền tống người giữ ngọc giản tới Quy Nhất Tông @c1786"],"tabs":{"tienTrinh":[{"chuong":"@c1786","loai":"xuất hiện","importance":"normal","giaiDoan":"Triệu tập sứ giả","text":"Âu Dương Chân giao ngọc giản cho Vương Lâm để sử dụng Truyền Tống Trận tới Quy Nhất Tông ba lần.","anchor":"Ngọc giản này đủ để sử dụng Truyền Tống Trận ba lần và có ghi chép vị trí cụ thể của Truyền Tống Trận"}]},"capNhatToi":"@c1786","nguon":["@c1786"]},{"id":"dai-tran-quy-nhat-tong","name":"Đại trận Quy Nhất Tông","cn":"","loai":"khac","loaiLabel":"Trận pháp hộ tông","phamCap":"Chưa rõ","hePhai":"Quy Nhất Tông","soHuu":["Quy Nhất Tông"],"blurb":"Đại trận bao quanh Quy Nhất Tông, được dùng để dẫn người đã được xác nhận thân phận vào trong tông. Vương Lâm và Đường Giai đi qua đại trận dưới sự dẫn đường của tu sĩ Quy Nhất Tông.","detail":"Đại trận xuất hiện khi nam tử trung niên Quy Nhất Tông dẫn nhóm Vương Lâm tiến vào khu vực trung tâm. Công năng cụ thể chưa được nói rõ ngoài vai trò bảo vệ và dẫn nhập tông môn.","congNang":["Bảo vệ và dẫn nhập người được tiếp dẫn vào Quy Nhất Tông @c1786"],"tabs":{"tienTrinh":[{"chuong":"@c1786","loai":"xuất hiện","importance":"normal","giaiDoan":"Dẫn vào tông môn","text":"Nam tử trung niên Quy Nhất Tông dẫn Vương Lâm và những người đi cùng bước vào đại trận để tới đại điện trung tâm.","anchor":"Dưới sự dẫn đường của nam tử trung niên này, họ bước vào trong đại trận của Quy Nhất Tông"}]},"capNhatToi":"@c1786","nguon":["@c1786"]},{"id":"thien-nguu-an-ky-khi-tuc-thien-nguu-hon","name":"Thiên Ngưu ấn ký / khí tức Thiên Ngưu Hồn","cn":"","aliases":["Thiên Ngưu ấn ký","khí tức Thiên Ngưu Hồn"],"loai":"than-thong","loaiLabel":"Ấn ký thần thông","phamCap":"Chưa rõ","hePhai":"Thiên Ngưu Châu","soHuu":["Vương Lâm","Đường Giai","Lão già tóc bạc dưới chuông lớn Quy Nhất Tông","Thanh niên dưới chuông lớn Quy Nhất Tông"],"blurb":"Dấu hiệu và khí tức liên quan Thiên Ngưu Hồn, hiện trên các Thiên Ngưu sứ giả. Nhờ khí tức này, Vương Lâm được tu sĩ Quy Nhất Tông nhận ra và kính cẩn tiếp đón.","detail":"Thiên Ngưu ấn ký xuất hiện trên mặt Vương Lâm, Đường Giai, lão già tóc bạc và thanh niên dưới chuông lớn. Khí tức Thiên Ngưu Hồn đi kèm giúp phân biệt thân phận Thiên Ngưu sứ giả trong lần tập trung tại Quy Nhất Tông.","congNang":["Giúp Quy Nhất Tông nhận biết thân phận Thiên Ngưu sứ giả @c1786"],"tabs":{"tienTrinh":[{"chuong":"@c1786","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhận diện sứ giả","text":"Tu sĩ Quy Nhất Tông cảm nhận khí tức Thiên Ngưu Hồn trên Vương Lâm và đổi sang cung kính tiếp đón hắn như Thiên Ngưu sứ giả.","anchor":"Bọn họ cảm nhận rất rõ trên người Vương Lâm tỏa ra một luồng khí tức của Thiên Ngưu Hồn"}]},"capNhatToi":"@c1786","nguon":["@c1786"]},{"id":"kim-dao-tu-tay-phai-van-dat-phong","name":"Kim đao từ tay phải Vân Dật Phong","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"Không rõ","hePhai":"Quy Nhất Tông","soHuu":["Vân Dật Phong"],"blurb":"Thuật công kích do Vân Dật Phong dùng khi tái ngộ Vương Lâm. Tay phải hóa đao, gom kim quang và tiên khí để chém xuống với uy thế rất mạnh.","detail":"Vân Dật Phong dùng tay phải hóa thành đao, khiến kim quang chói mắt tụ lại thành kim đao chém thẳng xuống Vương Lâm. Uy thế của đòn này làm những người dẫn đường vội lui, Đường Giai cũng tự nhận nếu không dùng Hồn Khải thì không chống nổi.","thuocTinh":"kim hệ","uyLuc":"Cắn nuốt tiên lực bốn phía, có uy thế khai thiên trong lần thi triển trước Vương Lâm.","dacDiem":"Kim quang hóa thành một thanh kim đao từ tay phải người thi triển.","nguoiTu":[{"ten":"Vân Dật Phong","tuChuong":"@c1787","tangDatToi":"Không rõ","trangThai":"đang dùng"}],"congNang":["Ngưng kim quang và tiên khí thành kim đao để chém mục tiêu @c1787"],"tabs":{"tienTrinh":[{"chuong":"@c1787","loai":"thi triển","importance":"normal","giaiDoan":"Thử sức Vương Lâm","text":"Vân Dật Phong dùng tay phải hóa thành kim đao chém xuống Vương Lâm, khiến nhiều người xung quanh phải lùi tránh.","anchor":"Kim quang vô cùng chói mắt, hóa thành một thanh kim đao chém thẳng xuống"}]},"capNhatToi":"@c1787","nguon":["@c1787"]},{"id":"cam-che-phong-toa-quang-truong-quy-nhat-tong","name":"Cấm chế phong tỏa quảng trường Quy Nhất Tông","cn":"","aliases":[],"loai":"cong-phap","loaiLabel":"Cấm chế","phamCap":"Không rõ","hePhai":"Quy Nhất Tông","soHuu":["Tông chủ Quy Nhất Tông","Quy Nhất Tông"],"blurb":"Cấm chế vô hình bao phủ quảng trường Quy Nhất Tông khi Tông chủ triệu tập nhóm giữ huyệt. Nó phong kín nơi nghị sự, ngăn nghe lén và đảo loạn thiên địa để chống suy tính.","detail":"Khi Tông chủ Quy Nhất Tông lên tiếng, Vương Lâm nhận ra nơi này đã bị cấm chế vô hình bao phủ hoàn toàn. Cấm chế không chỉ ngăn ngoại nhân nghe được nội dung bên trong mà còn làm thiên địa biến hóa, khiến người khác khó tính toán hay dự đoán.","thuocTinh":"phong cấm","nguonGoc":"Quy Nhất Tông","congNang":["Phong tỏa âm thanh và không gian nghị sự @c1787","Đảo loạn thiên địa để chống suy tính từ bên ngoài @c1787"],"tabs":{"tienTrinh":[{"chuong":"@c1787","loai":"xuất hiện","importance":"normal","giaiDoan":"Phong tỏa buổi triệu tập","text":"Cấm chế vô hình bao phủ quảng trường, phong kín nơi Tông chủ Quy Nhất Tông ban thưởng và giao nhiệm vụ.","anchor":"đã bị một cấm chế vô hình bao phủ. Bị phong ấn hoàn toàn"}]},"capNhatToi":"@c1787","nguon":["@c1787"]},{"id":"bon-loai-than-thong-truyen-thua-quy-nhat-tong","name":"Bốn loại thần thông truyền thừa Quy Nhất Tông","cn":"","aliases":[],"loai":"than-thong","loaiLabel":"Thần thông truyền thừa","phamCap":"Không rõ","hePhai":"Quy Nhất Tông","soHuu":["Quy Nhất Tông","Vân Dật Phong"],"blurb":"Hệ thần thông truyền thừa của Quy Nhất Tông, gồm bốn loại được Tông chủ nhắc tới khi ban thưởng. Vân Dật Phong được truyền một loại vì đã có Ngũ Hành Khải mộc hệ từ trước.","detail":"Trong buổi ban thưởng sau chiến sự Thiên Ngưu huyệt, Tông chủ Quy Nhất Tông không ban thêm Ngũ Hành Khải cho Vân Dật Phong mà chọn truyền cho hắn một trong bốn loại thần thông truyền thừa của bổn tông.","nguonGoc":"Quy Nhất Tông","congNang":["Là truyền thừa thần thông trọng yếu được Tông chủ dùng làm phần thưởng @c1787"],"nguoiTu":[{"ten":"Vân Dật Phong","tuChuong":"@c1787","tangDatToi":"Được truyền một loại","trangThai":"vừa nhận"}],"tabs":{"tienTrinh":[{"chuong":"@c1787","loai":"xuất hiện","importance":"normal","giaiDoan":"Ban truyền thừa","text":"Tông chủ Quy Nhất Tông truyền cho Vân Dật Phong một trong bốn loại thần thông truyền thừa của bổn tông.","anchor":"ta truyền cho ngươi một trong bốn loại thần thông truyền thừa của bổn tông"}]},"capNhatToi":"@c1787","nguon":["@c1787"]},{"id":"dai-tran-bat-dong-cua-quy-nhat-tong","name":"Đại trận bất động của Quy Nhất Tông","cn":"","loai":"khac","loaiLabel":"Trận pháp truyền tống","phamCap":"không rõ","hePhai":"Quy Nhất Tông","soHuu":["Quy Nhất Tông"],"blurb":"Đại trận của Quy Nhất Tông đã bất động cả vạn năm, được Tông chủ nói sẽ mở để đưa bốn người vào Lục Ma Châu.","detail":"Tông chủ Quy Nhất Tông tuyên bố sẽ thi triển thần thông mở đại trận này để đưa Vương Lâm, Vân Dật Phong, Biên Vân và Đường Giai vào Lục Ma Châu; điều kiện đi kèm là bốn người phải lưu lại một tia mệnh hồn để sau nhiệm vụ có thể được đưa trở về.","congNang":["Đưa người vào Lục Ma Châu và dựa vào mệnh hồn để kéo người trở về sau nhiệm vụ @c1788"],"tabs":{"tienTrinh":[{"chuong":"@c1788","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở đường vào Lục Ma Châu","text":"Tông chủ Quy Nhất Tông nói sẽ mở đại trận bất động cả vạn năm để đưa bốn người vào Lục Ma Châu, nhưng yêu cầu họ giao mệnh hồn trước.","anchor":"mở đại trận bất động cả vạn năm nayy của Quy Nhất Tông ta, đem bốn người các ngươi đưa vào Lục Ma Châu"}]},"capNhatToi":"@c1788","nguon":["@c1788"]},{"id":"hon-lenh","name":"Hồn Lệnh","cn":"","loai":"bi-thuat","loaiLabel":"Lệnh truy sát","phamCap":"không rõ","hePhai":"Quy Nhất Tông","soHuu":["Tông chủ Quy Nhất Tông","Quy Nhất Tông"],"blurb":"Hồn Lệnh là hiệu lệnh truy sát được phát ra sau khi Vương Lâm chống lại yêu cầu giao Hồn Khải.","detail":"Khi Hồn Lệnh được phát, Vương Lâm bị tuyên bố phản bội Thiên Ngưu Châu; mọi tu sĩ Thiên Ngưu Châu đều được phép tru sát hắn và nhận trọng thưởng.","congNang":["Ban bố lệnh truy sát toàn Thiên Ngưu Châu đối với người bị quy kết phản bội @c1788"],"tabs":{"tienTrinh":[{"chuong":"@c1788","loai":"xuất hiện","importance":"major","giaiDoan":"Truy sát Vương Lâm","text":"Tông chủ Quy Nhất Tông phát Hồn Lệnh, tuyên bố Vương Lâm phản bội Thiên Ngưu Châu và cho phép mọi tu sĩ trong châu tru sát hắn.","anchor":"Vương Lâm phản bội Thiên Ngưu Châu, phát Hồn Lệnh, phàm là tu sĩ Thiên Ngưu Châu ta"}]},"capNhatToi":"@c1788","nguon":["@c1788"]},{"id":"that-tinh-sat","name":"Thất Tinh sát","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"Không rõ","hePhai":"","soHuu":["Biên Vân"],"blurb":"Thần thông của Biên Vân, gọi bảy ngôi sao hiện giữa ban ngày rồi hóa thành thiên thạch rơi xuống mục tiêu.","detail":"Biên Vân thi triển Thất Tinh sát khi truy sát Vương Lâm ngoài sơn môn Quy Nhất Tông. Thần thông này ngưng tụ lực lượng thiên địa, biến bảy ngôi sao thành bảy thiên thạch khổng lồ đánh xuống phạm vi Vương Lâm.","congNang":["Gọi bảy thiên thạch rơi xuống phạm vi mục tiêu @c1789"],"nguoiTu":[{"ten":"Biên Vân","tuChuong":"@c1789","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1789","loai":"thi triển","importance":"normal","giaiDoan":"Truy sát Vương Lâm","text":"Biên Vân gọi bảy ngôi sao xuất hiện giữa ban ngày và hóa thành thiên thạch rơi xuống Vương Lâm.","anchor":"chỉ thấy trên vùng trời sáng ngời một màu xanh biếc lại xuất hiện bảy ngôi sao lấp lánh"}]},"capNhatToi":"@c1789","nguon":["@c1789"]},{"id":"bat-mon-phong","name":"Bát môn phong","cn":"","loai":"than-thong","loaiLabel":"Thần thông phong ấn","phamCap":"Không rõ","hePhai":"","soHuu":["Đường Giai"],"blurb":"Thần thông phong ấn của Đường Giai, biến ra tám kim môn để khóa mục tiêu.","detail":"Đường Giai thi triển Bát môn phong khi áp sát Biên Vân. Tám kim môn xuất hiện quanh Biên Vân, tạm thời phong ấn hành động của hắn và tạo cơ hội cho Vương Lâm quay lại phản kích.","congNang":["Phong ấn mục tiêu bằng tám kim môn @c1789"],"nguoiTu":[{"ten":"Đường Giai","tuChuong":"@c1789","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1789","loai":"thi triển","importance":"normal","giaiDoan":"Phong khóa Biên Vân","text":"Đường Giai biến ra tám kim môn quanh Biên Vân để tạm thời phong khóa hắn.","anchor":"Lập tức tám kim môn liền biến ảo ra bốn phía Biên Vân"}]},"capNhatToi":"@c1789","nguon":["@c1789"]},{"id":"luc-chi-ma-thu","name":"Lục chỉ ma thủ","aliases":["lục chỉ ma ấn"],"cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông công kích do Vương Lâm thi triển nối tiếp Thất Thải Thương trong trận đánh Biên Vân.","detail":"Lục chỉ ma thủ biến thành bàn tay khổng lồ, đánh tiếp lên lớp phòng ngự đã bị Thất Thải Thương làm suy yếu. Trong trận này, nó khiến tiểu thuẫn màu trắng của Biên Vân không còn sức chống cự và ép chưởng ấn rơi lên người hắn.","congNang":["Đánh xuyên phòng ngự sau khi mục tiêu đã bị thần thông khác áp chế @c1789"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1789","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1789","loai":"thi triển","importance":"normal","giaiDoan":"Liên kích Biên Vân","text":"Vương Lâm nối tiếp Thất Thải Thương bằng lục chỉ ma thủ khổng lồ để công phá phòng ngự của Biên Vân.","anchor":"lục chỉ ma thủ khổng lồ bất ngờ biến ảo ra"}]},"capNhatToi":"@c1789","nguon":["@c1789"]},{"id":"roi-vang-cua-duong-giai","name":"Roi vàng của Đường Giai","cn":"","loai":"than-thong","loaiLabel":"Thần thông công kích","phamCap":"Không rõ","hePhai":"","soHuu":["Đường Giai"],"blurb":"Thần thông hóa roi vàng khổng lồ của Đường Giai, dùng để phối hợp đánh Biên Vân.","detail":"Trong vùng thiên địa đen tối do Tàn Dạ tạo ra, Đường Giai kết thành một roi vàng khổng lồ. Đòn này quất trúng Biên Vân, tiếp tục đẩy hắn vào tình thế nguy hiểm.","congNang":["Kết thành roi vàng khổng lồ để quất trúng mục tiêu @c1789"],"nguoiTu":[{"ten":"Đường Giai","tuChuong":"@c1789","tangDatToi":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c1789","loai":"thi triển","importance":"normal","giaiDoan":"Phối hợp Tàn Dạ","text":"Đường Giai biến ra roi vàng khổng lồ trong bóng tối và quất trúng Biên Vân.","anchor":"bất ngờ xuất hiện một cái roi màu vàng khổng lồ"}]},"capNhatToi":"@c1789","nguon":["@c1789"]},{"id":"dao-co-luc","name":"Đạo Cổ lực","cn":"","loai":"than-thong","loaiLabel":"Lực lượng thân thể","phamCap":"không rõ","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Lực lượng Đạo Cổ được Vương Lâm ngưng tụ trong quyền kình khi đánh Biên Vân.","detail":"Một quyền ẩn chứa Đạo Cổ lực khiến thiên địa biến hóa và tạo tiếng chấn động vang vọng trong trận truy sát Biên Vân.","uyLuc":"Một quyền khiến thiên địa biến hóa.","congNang":["Gia trì quyền kình thân thể, tạo lực công kích trực diện mạnh mẽ @c1790"],"nguon":["@c1790"]},{"id":"tu-bao-khong-kiep-trung-ky","name":"Tự bạo Không Kiếp trung kỳ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không Kiếp trung kỳ","hePhai":"Lục Ma Châu","soHuu":["Lục Ma sứ giả thứ nhất","Lục Ma sứ giả thứ hai"],"blurb":"Thủ đoạn hủy diệt thân tu sĩ Không Kiếp trung kỳ, được hai Lục Ma sứ giả dùng liên tiếp để ngăn Vương Lâm. Uy lực khiến cả Không Kiếp hậu kỳ cũng không dám trực diện đón đỡ.","detail":"Hai Lục Ma sứ giả không giao chiến kéo dài mà lần lượt tự bạo ngay khi Vương Lâm lao tới, tạo hai đợt hủy diệt liên tiếp ở biên giới Lục Ma Châu. Chương nhấn mạnh uy lực này đủ khiến tu sĩ Không Kiếp hậu kỳ cũng phải lui tránh.","thuocTinh":"Hủy diệt thân tu sĩ","uyLuc":"Đe dọa cả tu sĩ Không Kiếp hậu kỳ nếu trực diện đón đỡ.","dacDiem":"Tự bạo liên tiếp tạo thành thế ngăn đường bất thường, cho thấy phía Lục Ma Châu có mục tiêu lớn hơn giao chiến thông thường.","congNang":["Tạo lực hủy diệt cực lớn bằng cách tự bạo thân tu sĩ Không Kiếp trung kỳ @c1792"],"nguoiTu":[{"ten":"Lục Ma sứ giả thứ nhất","tuChuong":"@c1792","tangDatToi":"Không Kiếp trung kỳ","trangThai":"đã tự bạo"},{"ten":"Lục Ma sứ giả thứ hai","tuChuong":"@c1792","tangDatToi":"Không Kiếp trung kỳ","trangThai":"đã tự bạo"}],"tabs":{"tienTrinh":[{"chuong":"@c1792","loai":"thi triển","importance":"normal","giaiDoan":"Hai sứ giả tự bạo","text":"Hai Lục Ma sứ giả Không Kiếp trung kỳ liên tiếp tự bạo để ngăn Vương Lâm tại biên giới Lục Ma Châu.","anchor":"Hai tu sĩ Không Kiếp trung kỳ tự bạo. Loại uy lực này dù là Không Kiếp hậu kỳ cung không dám đón đỡ mà phải lui lại phía sau né tránh!"}]},"capNhatToi":"@c1792","nguon":["@c1792"]},{"id":"kiem-khi-kinh-thien-cua-van-khong","name":"Kiếm khí kinh thiên của Vân Không","cn":"","loai":"than-thong","loaiLabel":"Thần thông kiếm đạo","phamCap":"Không rõ","hePhai":"Vân Không","soHuu":["Vân Không"],"blurb":"Thần thông kiếm đạo được Vân Không liên tục thi triển để chặn đường Vương Lâm trong vùng núi. Kiếm khí mạnh đến mức buộc Vương Lâm phải dùng quyền phá kiếm và làm áo giáp hai tay vỡ nát.","detail":"Vân Không đứng trên đỉnh núi cao nhất, liên tiếp chém ra kiếm khí kinh thiên nhằm trì hoãn Vương Lâm. Các kiếm ảnh khiến Vương Lâm phải áp sát bằng thân thể và song quyền thay vì thoát đi bằng tốc độ.","uyLuc":"Có thể phá hỏng phần áo giáp ở hai tay Vương Lâm trong lúc giao chiến.","dacDiem":"Thi triển liên hoàn để phong tỏa đường tiến của đối thủ.","congNang":["Tạo kiếm khí công kích liên tiếp để cản đường và tiêu hao phòng ngự của đối phương @c1793"],"nguoiTu":[{"ten":"Vân Không","tuChuong":"@c1793","tangDatToi":"Thi triển trong giao chiến","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1793","loai":"thi triển","importance":"normal","giaiDoan":"Chặn Vương Lâm trong vùng núi","text":"Vân Không liên tục chém ra kiếm khí để cản Vương Lâm, buộc đối phương dùng quyền phá kiếm trong lúc áo giáp hai tay bị tổn hại.","anchor":"Trong nháy mắt khi Vương Lâm xé gió lao tới, tay phải Vân Không bỗng nhiên giơ lên"}]},"capNhatToi":"@c1793","nguon":["@c1793"]},{"id":"chin-kiem-anh-mau-vang-cua-van-khong","name":"Chín kiếm ảnh máu vàng của Vân Không","cn":"","loai":"than-thong","loaiLabel":"Thần thông huyết khí kiếm đạo","phamCap":"Không rõ","hePhai":"Vân Không","soHuu":["Vân Không"],"blurb":"Thần thông dùng máu vàng hóa thành chín kiếm ảnh của Vân Không. Chiêu này được thi triển trước khi hắn dùng thanh kiếm cổ kính màu vàng kim đánh nhát cuối.","detail":"Vân Không cắn đầu lưỡi phun ra máu tươi màu vàng kim, khiến máu hóa thành chín kiếm ảnh lao về phía Vương Lâm. Đây là một phần trong chuỗi công kích cuối cùng nhằm tiếp tục trì hoãn Vương Lâm.","thuocTinh":"Huyết khí màu vàng kim, kiếm ảnh","congNang":["Biến máu vàng thành chín kiếm ảnh công kích đối thủ @c1793"],"nguoiTu":[{"ten":"Vân Không","tuChuong":"@c1793","tangDatToi":"Thi triển trong giao chiến","trangThai":"đã thi triển"}],"tabs":{"tienTrinh":[{"chuong":"@c1793","loai":"thi triển","importance":"normal","giaiDoan":"Trước nhát kiếm cuối","text":"Vân Không dùng máu vàng hóa thành chín kiếm ảnh lao thẳng về phía Vương Lâm.","anchor":"Ngụm máu tươi này màu vàng kim, hình thành chín kiếm ảnh bay thẳng về phía Vương Lâm"}]},"capNhatToi":"@c1793","nguon":["@c1793"]},{"id":"truyen-tong-tran-cua-dao-ma-tong","name":"Truyền Tống Trận của Đạo Ma Tông","cn":"","loai":"cong-phap","loaiLabel":"Trận pháp truyền tống","phamCap":"Không rõ","hePhai":"Đạo Ma Tông","soHuu":["Đạo Ma Tông"],"blurb":"Truyền Tống Trận của Đạo Ma Tông là bảy trận pháp truyền tống được mở gần biên giới Mạnh Thổ Châu. Chúng đưa hơn trăm tu sĩ Đạo Ma Tông tới chặn đường Vương Lâm với cái giá tiêu hao cực lớn.","detail":"Khi Vương Lâm chỉ còn cách Mạnh Thổ Châu chưa tới ngàn dặm, bảy vị trí gần biên giới bỗng lan ra ánh sáng truyền tống. Hơn trăm tu sĩ Đạo Ma Tông theo đó xuất hiện để chặn đường mục tiêu, cho thấy Đạo Ma Tông chấp nhận trả giá lớn nhằm na di lực lượng tới điểm cần thiết @c1793.","congNang":["Na di nhiều tu sĩ tới biên giới để chặn đường mục tiêu @c1793"],"tabs":{"tienTrinh":[{"chuong":"@c1793","loai":"xuất hiện","importance":"major","giaiDoan":"Chặn biên Mạnh Thổ Châu","text":"Bảy Truyền Tống Trận mở ra gần biên giới Mạnh Thổ Châu, đưa hơn trăm tu sĩ Đạo Ma Tông tới chặn Vương Lâm.","anchor":"Phía trước Vương Lâm chợt xuất hiện bảy vị trí lan ra ánh sáng chói mắt"}]},"capNhatToi":"@c1793","nguon":["@c1793"]}]};